  //   Gốc lỗi: _yqIdbGetChatId có thể trả null khi ST chưa ready (sau sửa).
  //         Nếu không bảo vệ, store.put(value, null + "/" + key) -> dữ liệu ghi vào key sai.
  //   Sửa: chatId là null thì bỏ qua ghi IDB, cache vẫn cập nhật (để luồng read-modify-write không vỡ).
  var _putChatId = _yqIdbGetChatId();
  if (!_putChatId) {
    try {
      console.warn(
        "[IDB ghi] chatId không dùng được, bỏ qua ghi IDB cho " +
          metaKey +
          " (dữ liệu được giữ trong cache bộ nhớ)",
      );
    } catch (_) {}
    _yqIdbCache[metaKey] = value;
    return;
  }
  _yqIdbCache[metaKey] = value;
  if (_yqIdbFailed) return;
  if (
    typeof _phoneMetaTxnState !== "undefined" &&
    _phoneMetaTxnState.rollbackLock
  )
    return;
  _yqIdbInit().then(function (db) {
    if (!db) return;
    try {
      var tx = db.transaction(YQ_IDB_STORE, "readwrite");
      var store = tx.objectStore(YQ_IDB_STORE);
      store.put(value, _yqIdbKey(metaKey));
    } catch (_e) {}
  });
