// [V10.4•2026-05-13] Thu hồi iframe lười (inject vào trang chính để tránh vấn đề IntersectionObserver xuyên iframe).
// Vấn đề: mỗi message có regex làm đẹp bảng đẩy tiến độ + khung gập Sakura, mỗi cái tạo 1 iframe.
//         50 vòng đối thoại = hơn 100 iframe, mỗi iframe chiếm 20-60KB DOM + bộ nhớ Vue instance.
// Giải pháp: inject script vào trang chính, dùng IntersectionObserver theo dõi iframe trong #chat.
//             Rời viewport 30 giây thì thay bằng div placeholder nhẹ (giữ chiều cao), cuộn về thì khôi phục.
(function _yqInjectIframeRecycle() {
  try {
    var _topWin = window.parent || window;
    var _topDoc = _topWin.document;
    if (!_topDoc || typeof _topWin.IntersectionObserver === "undefined") return;
    // Chống inject trùng.
    if (_topWin._yqIframeRecycleInjected) return;
    _topWin._yqIframeRecycleInjected = true;

    var script = _topDoc.createElement("script");
    script.textContent =
      "(" +
      function () {
        if (window._yqIframeRecycleRunning) return;
        window._yqIframeRecycleRunning = true;
        var DELAY = 30000;
        var timers = new WeakMap();
        var count = 0;

        var observer = new IntersectionObserver(
          function (entries) {
            for (var i = 0; i < entries.length; i++) {
              var entry = entries[i];
              var el = entry.target;
              if (entry.isIntersecting) {
                var t = timers.get(el);
                if (t) {
                  clearTimeout(t);
                  timers.delete(el);
                }
              } else {
                if (!timers.has(el)) {
                  timers.set(
                    el,
                    setTimeout(function () {
                      timers.delete(el);
                      recycle(el);
                    }, DELAY),
                  );
                }
              }
            }
          },
          { root: null, rootMargin: "300px" },
        );

        function recycle(ifr) {
          try {
            if (!ifr || !ifr.parentNode) return;
            if (!ifr.closest || !ifr.closest(".mes")) return;
            if (!ifr.src || ifr.src.indexOf("blob:") !== 0) return;
            try {
              var fw = ifr.contentWindow;
              if (
                fw &&
                (typeof fw._yqRefreshPanel === "function" ||
                  typeof fw.phoneAPI !== "undefined")
              )
                return;
            } catch (e) {}
            var h = Math.max(ifr.offsetHeight || 50, 50);
            var div = document.createElement("div");
            div.className = "yq-iframe-placeholder";
            div.style.cssText =
              "width:100%;height:" +
              h +
              "px;background:rgba(6,16,29,0.6);border:1px dashed rgba(125,211,252,0.2);border-radius:12px;display:flex;align-items:center;justify-content:center;color:rgba(125,211,252,0.5);font-size:12px;cursor:pointer;";
            div.textContent =
              "\ud83d\udccb Bấm để mở bảng đẩy tiến độ";
            div.dataset.src = ifr.src;
            div.dataset.h = String(h);
            div.onclick = function () {
              var nf = document.createElement("iframe");
              nf.src = div.dataset.src;
              nf.style.cssText =
                "width:100%;height:" + div.dataset.h + "px;border:none;";
              div.parentNode.replaceChild(nf, div);
              observer.observe(nf);
              count--;
            };
            ifr.parentNode.replaceChild(div, ifr);
            observer.unobserve(ifr);
            count++;
            console.log(
              "[thu hồi iframe] đã thu hồi 1 iframe tầng cũ (tổng cộng " +
                count +
                " cái)",
            );
          } catch (e) {}
        }

        function scan() {
          var chat = document.getElementById("chat");
          if (!chat) return;
          var ifs = chat.querySelectorAll('.mes iframe[src^="blob:"]');
          for (var i = 0; i < ifs.length; i++) observer.observe(ifs[i]);
        }

        var chat = document.getElementById("chat");
        if (chat) {
          new MutationObserver(function (muts) {
            for (var i = 0; i < muts.length; i++) {
              var added = muts[i].addedNodes;
              for (var j = 0; j < added.length; j++) {
                if (added[j].nodeType === 1 && added[j].querySelectorAll) {
                  var nf = added[j].querySelectorAll('iframe[src^="blob:"]');
                  for (var k = 0; k < nf.length; k++) observer.observe(nf[k]);
                }
              }
            }
          }).observe(chat, { childList: true, subtree: true });
        }
        setTimeout(scan, 10000);
      }.toString() +
      ")();";
    _topDoc.head.appendChild(script);
    try {
      console.log("[thu hồi iframe] đã inject script thu hồi vào trang chính");
    } catch (_) {}
  } catch (_e) {
    try {
      console.warn("[thu hồi iframe] inject thất bại:", _e);
    } catch (_) {}
  }
})();


