// ==================== Hàm công cụ giới hạn biên ====================
// Hàm clamp: giới hạn giá trị giữa min và max.
function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

// Lấy kích thước viewport đáng tin cậy (hỗ trợ iframe và nhiều môi trường).
function getViewportSize() {
  // Ưu tiên dùng visualViewport (chính xác hơn, hỗ trợ zoom).
  if (window.visualViewport) {
    const vv = window.visualViewport;
    if (vv.width > 0 && vv.height > 0) {
      return { width: vv.width, height: vv.height };
    }
  }

  // Fallback về innerWidth/innerHeight.
  let w = window.innerWidth || document.documentElement.clientWidth || 0;
  let h = window.innerHeight || document.documentElement.clientHeight || 0;

  // Trong iframe thì thử cửa sổ cha.
  if ((w === 0 || h === 0) && window.parent !== window) {
    try {
      const pw =
        window.parent.innerWidth ||
        window.parent.document.documentElement.clientWidth;
      const ph =
        window.parent.innerHeight ||
        window.parent.document.documentElement.clientHeight;
      if (pw > 0) w = pw;
      if (ph > 0) h = ph;
    } catch (e) {
      // Cross-domain không truy cập được cửa sổ cha.
    }
  }

  // Fallback cuối về giá trị mặc định (tránh trả 0).
  return {
    width: w > 0 ? w : 800,
    height: h > 0 ? h : 600,
  };
}

// Giới hạn vị trí element trong viewport (bảo đảm ít nhất minVisible pixel còn thấy được).
function constrainToViewport(
  x,
  y,
  elementWidth,
  elementHeight,
  minVisible = 20,
) {
  const viewport = getViewportSize();

  // Bảo đảm ít nhất minVisible pixel nằm trong màn hình.
  const boundedX = clamp(
    x,
    -elementWidth + minVisible,
    viewport.width - minVisible,
  );
  const boundedY = clamp(
    y,
    -elementHeight + minVisible,
    viewport.height - minVisible,
  );

  return { x: boundedX, y: boundedY };
}

// Giới hạn hoàn toàn trong viewport (không cho phần nào vượt ra ngoài).
function constrainFullyInViewport(x, y, elementWidth, elementHeight) {
  const viewport = getViewportSize();

  const boundedX = clamp(x, 0, viewport.width - elementWidth);
  const boundedY = clamp(y, 0, viewport.height - elementHeight);

  return { x: boundedX, y: boundedY };
}

