  // Mời nhân vật từ danh bạ vào nhóm chat hiện có (nhân vật chính chủ động kéo người vào nhóm)
  $("body")
    .off("click.socialInviteGroup")
    .on(
      "click.socialInviteGroup",
      ".contact-action-invite-group",
      function (e) {
        e.preventDefault();
        e.stopPropagation();
        var targetName = String($(this).data("name") || "").trim();
        if (!targetName) return;

        // Lấy tất cả nhóm chat hiện có
        var groups = (typeof getSavedGroups === "function") ? getSavedGroups() : (getPhoneMeta("groups", {}) || {});
        var groupKeys = Object.keys(groups);
        if (groupKeys.length === 0) {
          yqToast("warning", "Hãy tạo nhóm chat trước (trang Tin nhắn -> tab Nhóm chat -> Tạo nhóm chat)");
          return;
        }

        // Lọc ra các nhóm mà nhân vật này chưa tham gia
        var availableGroups = [];
        for (var gi = 0; gi < groupKeys.length; gi++) {
          var gid = groupKeys[gi];
          var grp = groups[gid];
          if (!grp) continue;
          var members = String(grp.members || "").split(/[、,，]/).map(function(s){ return s.trim(); }).filter(Boolean);
          if (members.indexOf(targetName) < 0) {
            availableGroups.push({ id: gid, name: grp.name || gid, members: members });
          }
        }

        if (availableGroups.length === 0) {
          yqToast("info", "\"" + targetName.replace(/_/g, " ") + "\" đã ở trong tất cả nhóm chat");
          return;
        }

        // Bật popup chọn nhóm
        var html = '<div id="yq-invite-group-modal" style="position:fixed;inset:0;background:rgba(0,0,0,0.6);z-index:100000;display:flex;align-items:center;justify-content:center">';
        html += '<div style="background:#1a1a2e;border:1px solid rgba(255,255,255,0.1);border-radius:12px;max-width:320px;width:85%;padding:16px;max-height:60vh;overflow-y:auto">';
        html += '<div style="font-size:14px;font-weight:700;color:#e2e8f0;margin-bottom:10px">👥 Chọn nhóm chat muốn kéo "' + escapeHtml(targetName.replace(/_/g, " ")) + '" vào</div>';
        for (var ai = 0; ai < availableGroups.length; ai++) {
          var ag = availableGroups[ai];
          html += '<button type="button" class="yq-invite-grp-pick" data-gid="' + escapeHtml(ag.id) + '" data-target="' + escapeHtml(targetName) + '" style="display:block;width:100%;text-align:left;padding:10px 12px;margin-bottom:4px;font-size:13px;color:#e2e8f0;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.06);border-radius:6px;cursor:pointer">';
          html += '<div style="font-weight:600">' + escapeHtml(ag.name) + '</div>';
          html += '<div style="font-size:11px;color:#9ca3af;margin-top:2px">Thành viên: ' + escapeHtml(ag.members.slice(0, 5).map(function(m){ return String(m || "").replace(/_/g, " "); }).join("、")) + (ag.members.length > 5 ? "..." : "") + '</div>';
          html += '</button>';
        }
        html += '<div style="margin-top:8px"><button type="button" id="yq-invite-grp-close" class="yq-btn yq-btn--ghost-dark yq-btn--block" style="min-height:38px;font-size:12px;">Hủy</button></div>';
        html += '</div></div>';

        $("#yq-invite-group-modal").remove();
        $("body").append(html);

        // Đóng popup
        $("#yq-invite-grp-close, #yq-invite-group-modal").on("click", function(ev) {
          if (ev.target === this) $("#yq-invite-group-modal").remove();
        });

        // Sau khi chọn nhóm chat thì thực hiện kéo người
        $(".yq-invite-grp-pick").on("click", function(ev) {
          ev.stopPropagation();
          var gid = String($(this).data("gid") || "");
          var target = String($(this).data("target") || "");
          if (!gid || !target) return;
          var grps = (typeof getSavedGroups === "function") ? getSavedGroups() : {};
          var grp = grps[gid];
          if (!grp) return;
          var mList = String(grp.members || "").split(/[、,，]/).map(function(s){ return s.trim(); }).filter(Boolean);
          if (mList.indexOf(target) >= 0) { yqToast("info", "Đã ở trong nhóm"); $("#yq-invite-group-modal").remove(); return; }
          mList.push(target);
          grp.members = mList.join("、");
          grps[gid] = grp;
          if (typeof setSavedGroups === "function") setSavedGroups(grps);
          if (typeof debounceSavePhoneMeta === "function") debounceSavePhoneMeta();
          // Chèn tin hệ thống vào nhóm chat
          try {
            var gen = window.npcMsgGen;
            if (gen) gen.storeNpcMessage("group_" + gid, "Tin hệ thống", "\"" + target.replace(/_/g, " ") + "\" đã được mời vào nhóm chat", true);
          } catch(_e) {}
          yqToast("success", "Đã kéo \"" + target.replace(/_/g, " ") + "\" vào \"" + String(grp.name || gid).replace(/_/g, " ") + "\"");
          $("#yq-invite-group-modal").remove();
          // Làm mới bảng tin nhắn
          if (currentPanel === "messages" && currentPhoneData) {
            $("#phone-app-body").html(generateMessagesPanel(currentPhoneData));
            if (typeof bindPanelButtons === "function") bindPanelButtons();
          }
        });
      },
    );

