  // Tin nhắn chat - tạo thủ công ảnh đang chờ tạo (có tag nhưng chưa có ảnh)
  $(document).on("click.phoneDoc", ".chat-gen-pending-img-btn", function (e) {
    e.stopPropagation();
    e.preventDefault();
    var imageId = $(this).data("image-id");
    if (!imageId || !window.phoneImageStore) return;
    var $btn = $(this);
    var entry = window.phoneImageStore.getEntry(imageId);
    if (!entry || !entry.tag) {
      yqToast("warning", "tag chưa sẵn sàng");
      return;
    }
    var _pendingKey =
      typeof window.phoneMakeChatImagePendingKey === "function"
        ? window.phoneMakeChatImagePendingKey(imageId)
        : "chat:image:" + String(imageId || "");
    if (typeof window.phoneSetManualImagePending === "function")
      window.phoneSetManualImagePending(_pendingKey, true);
    if (typeof window.phoneQueueBtnStateUpdate === "function") {
      window.phoneQueueBtnStateUpdate(function () {
        $btn
          .prop("disabled", true)
          .html('<i class="fas fa-spinner fa-spin"></i> Đang tạo...');
      });
    } else {
      $btn
        .prop("disabled", true)
        .html('<i class="fas fa-spinner fa-spin"></i> Đang tạo...');
    }
    // [V10.1 FIX] Bọc try-catch để tránh pending kẹt vĩnh viễn khi phoneRenderImage chưa định nghĩa
    var _renderPromise;
    try {
      if (typeof window.phoneRenderImage !== "function") throw new Error("phoneRenderImage chưa sẵn sàng");
      _renderPromise = window.phoneRenderImage(entry.tag, {
        entryId: imageId,
        source: "chat",
        size: entry.size,
      });
    } catch (_syncErr) {
      $btn.prop("disabled", false).html('<i class="fas fa-paint-brush"></i> 🎨 Tạo ảnh');
      if (typeof window.phoneSetManualImagePending === "function")
        window.phoneSetManualImagePending(_pendingKey, false);
      yqToast("error", "Chức năng tạo ảnh chưa sẵn sàng: " + (_syncErr.message || ""));
      return;
    }
    _renderPromise
      .then(function (r) {
        if (r && r.success) {
          // Làm mới giao diện chat
          if (window.currentChatContactId) {
            window.renderChatMessages._isFirstRender = true;
            window.renderChatMessages(
              window.currentChatContactId,
              window.currentChatIsGroup,
            );
          }
          yqToast("success", "Ảnh đã được tạo");
        } else {
          $btn
            .prop("disabled", false)
            .html('<i class="fas fa-paint-brush"></i> 🎨 Tạo ảnh');
          if (typeof toastr !== "undefined")
            yqToast("error", "Tạo thất bại: " + ((r && r.error) || ""));
        }
      })
      .catch(function () {
        $btn
          .prop("disabled", false)
          .html('<i class="fas fa-paint-brush"></i> 🎨 Tạo ảnh');
      })
      .finally(function () {
        if (typeof window.phoneSetManualImagePending === "function")
          window.phoneSetManualImagePending(_pendingKey, false);
      });
  });

  // Tin nhắn chat - tạo thủ công ảnh được AI mô tả (có imageDesc nhưng chưa có imageId)
  $(document).on("click.phoneDoc", ".chat-gen-desc-img-btn", function (e) {
    e.stopPropagation();
    e.preventDefault();
    var desc = $(this).data("desc");
    var sender = $(this).data("sender");
    var chatId = $(this).data("chat-id");
    var msgTs = parseInt($(this).data("msg-ts")) || 0;
    if (!desc) return;
    var $btn = $(this);
    var _pendingDescKey =
      typeof window.phoneMakeChatDescPendingKey === "function"
        ? window.phoneMakeChatDescPendingKey(chatId, msgTs, desc)
        : "chat:desc:" +
          String(chatId || "") +
          ":" +
          String(msgTs || 0) +
          ":" +
          String(desc || "");
    if (typeof window.phoneSetManualImagePending === "function")
      window.phoneSetManualImagePending(_pendingDescKey, true);
    $btn
      .prop("disabled", true)
      .html('<i class="fas fa-spinner fa-spin"></i> Đang tạo...');
    var _chatImgCtx =
      typeof window.buildChatImageGenContext === "function"
        ? window.buildChatImageGenContext(desc, sender, chatId, "")
        : { description: desc, chatContext: "" };
    // [V10.1 FIX] Bọc try-catch để tránh pending kẹt vĩnh viễn khi phoneGenerateImage chưa định nghĩa
    var _genPromise;
    try {
      if (typeof window.phoneGenerateImage !== "function") throw new Error("phoneGenerateImage chưa sẵn sàng");
      _genPromise = window.phoneGenerateImage("chat", _chatImgCtx);
    } catch (_syncErr) {
      $btn.prop("disabled", false).html('<i class="fas fa-paint-brush"></i> 🎨 Tạo ảnh');
      if (typeof window.phoneSetManualImagePending === "function")
        window.phoneSetManualImagePending(_pendingDescKey, false);
      yqToast("error", "Chức năng tạo ảnh chưa sẵn sàng: " + (_syncErr.message || ""));
      return;
    }
    _genPromise
      .then(function (r) {
        if (r && r.success) {
          // Dùng timestamp để định vị tin gốc trong chat_history rồi cập nhật imageId
          try {
            var ac = window.getPhoneMetaBig("chat_history", {});
            var ch = ac[chatId] || [];
            var found = false;
            for (var ci = ch.length - 1; ci >= 0; ci--) {
              if (ch[ci].imageDesc === desc && !ch[ci].imageId) {
                if (
                  msgTs &&
                  ch[ci].time &&
                  Math.abs(ch[ci].time - msgTs) < 5000
                ) {
                  ch[ci].isImage = true;
                  ch[ci].imageId = r.imageId || r.entryId;
                  found = true;
                  break;
                } else if (!msgTs) {
                  ch[ci].isImage = true;
                  ch[ci].imageId = r.imageId || r.entryId;
                  found = true;
                  break;
                }
              }
            }
            // Khi khớp timestamp thất bại thì fallback: tìm tin chưa có ảnh đầu tiên khớp desc
            if (!found) {
              for (var ci2 = ch.length - 1; ci2 >= 0; ci2--) {
                if (ch[ci2].imageDesc === desc && !ch[ci2].imageId) {
                  ch[ci2].isImage = true;
                  ch[ci2].imageId = r.imageId || r.entryId;
                  found = true;
                  break;
                }
              }
            }
            if (found) {
              ac[chatId] = ch;
              window.setPhoneMetaBig("chat_history", ac);
            }
          } catch (e) {}
          // Làm mới giao diện chat
          if (window.currentChatContactId === chatId) {
            window.renderChatMessages._isFirstRender = true;
            window.renderChatMessages(
              window.currentChatContactId,
              window.currentChatIsGroup,
            );
          }
          yqToast("success", "Ảnh đã được tạo");
        } else {
          $btn
            .prop("disabled", false)
            .html('<i class="fas fa-paint-brush"></i> 🎨 Tạo ảnh');
          if (typeof toastr !== "undefined")
            yqToast("error", "Tạo thất bại: " + ((r && r.error) || ""));
        }
      })
      .catch(function () {
        $btn
          .prop("disabled", false)
          .html('<i class="fas fa-paint-brush"></i> 🎨 Tạo ảnh');
      })
      .finally(function () {
        if (typeof window.phoneSetManualImagePending === "function")
          window.phoneSetManualImagePending(_pendingDescKey, false);
      });
  });

