  // Nhấp thumbnail album -> xem ảnh lớn (hỗ trợ lật trang)
  $(document).on("click.phoneDoc", ".gallery-thumb", function (e) {
    e.preventDefault();
    var imageId = $(this).data("image-id");
    var origin = $(this).data("origin");
    if (!imageId) return;

    // Dựng danh sách ảnh đang hiển thị để lật trang
    var $allThumbs = $(".gallery-thumb");
    var imageList = [];
    var currentIndex = -1;
    $allThumbs.each(function (i) {
      var tid = $(this).data("image-id");
      var torigin = $(this).data("origin");
      if (!tid) return;
      var tUrl = null,
        tId = null;
      if (torigin === "plugin") {
        tUrl = $(this).find("img").attr("src") || null;
        tId = null;
      } else {
        if (window.phoneImageStore) {
          tUrl = window.phoneImageStore.load(tid);
          tId = tid;
        }
      }
      if (tUrl) {
        if (tid === imageId) currentIndex = imageList.length;
        imageList.push({ url: tUrl, id: tId });
      }
    });

    if (origin === "plugin") {
      var imgData = $(this).find("img").attr("src") || null;
      if (imgData && window.viewFullImage)
        window.viewFullImage(
          imgData,
          null,
          imageList.length > 1 ? imageList : null,
          currentIndex,
        );
    } else {
      if (!window.phoneImageStore) return;
      var imgData2 = window.phoneImageStore.load(imageId);
      if (imgData2 && window.viewFullImage)
        window.viewFullImage(
          imgData2,
          imageId,
          imageList.length > 1 ? imageList : null,
          currentIndex,
        );
    }
  });

