  // Nhấp mục danh sách bạn bè (dùng ủy quyền sự kiện)
  // ==================== Sự kiện App livestream ====================
  function _yqOpenImageFromElement($img) {
    if (!$img || $img.length === 0 || !window.viewFullImage) return;
    var imageId = $img.data("image-id");
    if (imageId && window.phoneImageStore) {
      try {
        var cached = window.phoneImageStore.load(imageId);
        if (cached) {
          window.viewFullImage(cached, imageId);
          return;
        }
      } catch (_imgLoadErr) {}
    }
    var src = $img.attr("src");
    if (src) window.viewFullImage(src, imageId || null);
  }

  // Ảnh tổng quan giám sát - nhấp một lần để xem ảnh lớn
