    /* Nhấp avatar: chưa có avatar -> menu chọn, có avatar -> ảnh lớn + nút tùy biến */
    /* Hàm xử lý upload avatar (dùng chung cho menu nhấp và nút ảnh lớn) */
    function _handleAvatarUpload(charName) {
      var $fileInput = $("#char-avatar-upload-input");
      if (!$fileInput.length) return;
      $fileInput.off("change").on("change", function (ev) {
        var file = ev.target.files[0];
        $fileInput.val("");
        if (!file) return;
        if (!file.type.startsWith("image/")) {
          yqToast("error", "Hãy chọn file ảnh");
          return;
        }
        var reader = new FileReader();
        reader.onload = function (re) {
          var img = new Image();
          img.onload = function () {
            /* Canvas cắt giữa và scale về 512x512 */
            var canvas = document.createElement("canvas");
            canvas.width = 512;
            canvas.height = 512;
            var ctx = canvas.getContext("2d");
            var sw = img.width,
              sh = img.height;
            var scale = Math.max(512 / sw, 512 / sh);
            var dw = sw * scale,
              dh = sh * scale;
            var dx = (512 - dw) / 2,
              dy = (512 - dh) / 2;
            ctx.drawImage(img, 0, 0, sw, sh, dx, dy, dw, dh);
            var base64 = canvas.toDataURL("image/png");
            /* Dọn dữ liệu avatar cũ */
            try {
              var oldAvatars = getPhoneMeta("chat_avatars", {});
              var oldId = oldAvatars[charName];
              if (oldId && window.phoneImageStore) {
                window.phoneImageStore.remove(oldId);
              }
            } catch (_ce) {}
            /* Lưu vào phoneImageStore + chat_avatars */
            if (window.phoneImageStore) {
              var imageId = window.phoneImageStore.save(base64, {
                source: "avatar",
                description: String(charName).replace(/_/g, " ") + " avatar tùy biến",
                tag: "avatar",
                size: { w: 512, h: 512 },
              });
              var avatars = getPhoneMeta("chat_avatars", {});
              avatars[charName] = imageId;
              setPhoneMeta("chat_avatars", avatars);
              debounceSavePhoneMeta();
              yqToast("success", "Avatar của \"" + String(charName).replace(/_/g, " ") + "\" đã cập nhật");
              $("#phone-app-body").html(generateCharacterAppPanel());
              bindPanelButtons();
            } else {
              yqToast("error", "Không thể dùng bộ lưu ảnh");
            }
          };
          img.onerror = function () {
            yqToast("error", "Tải ảnh thất bại, hãy chọn ảnh hợp lệ");
          };
          img.src = re.target.result;
        };
        reader.onerror = function () {
          yqToast("error", "Đọc file thất bại");
        };
        reader.readAsDataURL(file);
      });
      $fileInput.click();
    }
    var _avatarClickTimer = null;
    $body
      .find(".char-avatar-wrap")
      .off("click dblclick")
      .on("click", function (e) {
        e.preventDefault();
        e.stopPropagation();
        var $wrap = $(this);
        var name = $wrap.data("name");
        if (_avatarClickTimer) {
          clearTimeout(_avatarClickTimer);
          _avatarClickTimer = null;
          return;
        }
        _avatarClickTimer = setTimeout(function () {
          _avatarClickTimer = null;
          var avatarUrl =
            typeof getCharacterAvatar === "function"
              ? getCharacterAvatar(name)
              : null;
          if (!avatarUrl) {
            /* Chưa có avatar: bật menu chọn */
            var menu = $(
              '<div style="position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);z-index:100000;display:flex;align-items:center;justify-content:center;">' +
                '<div style="background:#1e293b;border:1px solid #475569;border-radius:12px;padding:20px;min-width:220px;text-align:center;">' +
                '<div style="color:#e2e8f0;font-size:14px;font-weight:600;margin-bottom:16px;">Đặt avatar cho "' +
                escapeHtml(String(name).replace(/_/g, " ")) +
                '"</div>' +
                '<button type="button" class="_avatar-menu-upload yq-btn yq-btn--info yq-btn--block" style="margin-bottom:8px;font-size:13px;border-radius:10px;"><i class="fas fa-upload"></i> Upload avatar tùy biến</button>' +
                '<button type="button" class="_avatar-menu-aigen yq-btn yq-btn--amber yq-btn--block" style="margin-bottom:8px;font-size:13px;border-radius:10px;"><i class="fas fa-magic"></i> AI tạo avatar</button>' +
                '<button type="button" class="_avatar-menu-cancel yq-btn yq-btn--surface-600 yq-btn--block" style="font-size:13px;border-radius:10px;">Hủy</button>' +
                "</div></div>",
            );
            menu.find("._avatar-menu-cancel").on("click", function () {
              menu.remove();
            });
            menu.on("click", function (ev) {
              if (ev.target === menu[0]) menu.remove();
            });
            menu.find("._avatar-menu-upload").on("click", function () {
              menu.remove();
              _handleAvatarUpload(name);
            });
            menu.find("._avatar-menu-aigen").on("click", function () {
              menu.remove();
              if (!window.PhoneCharacterAppearance) {
                yqToast("error", "Module hình tượng nhân vật không khả dụng");
                return;
              }
              var $w = $wrap;
              $w.css("opacity", "0.5");
              window.PhoneCharacterAppearance.generateAvatar(name).then(
                function (r) {
                  $w.css("opacity", "1");
                  if (r.success) {
                    yqToast("success", "Avatar của \"" + String(name).replace(/_/g, " ") + "\" đã được tạo");
                    $("#phone-app-body").html(generateCharacterAppPanel());
                    bindPanelButtons();
                  } else {
                    yqToast("error", "Tạo avatar thất bại: " + (r.error || ""));
                  }
                },
              );
            });
            $("body").append(menu);
            return;
          }
          /* Có avatar: ảnh lớn toàn màn hình + nút tùy biến ở trên */
          var overlay = $(
            '<div style="position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.85);z-index:100000;display:flex;flex-direction:column;align-items:center;justify-content:center;">' +
              '<div style="position:absolute;top:16px;right:16px;display:flex;gap:8px;">' +
              '<button type="button" class="_avatar-overlay-upload yq-btn yq-btn--info" style="font-size:12px;border-radius:10px;"><i class="fas fa-upload"></i> Avatar tùy biến</button>' +
              "</div>" +
              '<img src="' +
              avatarUrl +
              '" style="max-width:90%;max-height:80%;border-radius:8px;object-fit:contain;">' +
              "</div>",
          );
          overlay.on("click", function (ev) {
            if (ev.target === overlay[0]) overlay.remove();
          });
          overlay.find("._avatar-overlay-upload").on("click", function (ev) {
            ev.stopPropagation();
            overlay.remove();
            _handleAvatarUpload(name);
          });
          $("body").append(overlay);
        }, 250);
      })
      .on("dblclick", function (e) {
        e.preventDefault();
        e.stopPropagation();
        if (_avatarClickTimer) {
          clearTimeout(_avatarClickTimer);
          _avatarClickTimer = null;
        }
        var name = $(this).data("name");
        if (!name || !window.PhoneCharacterAppearance) return;
        if (!confirm("Tạo lại avatar cho \"" + String(name).replace(/_/g, " ") + "\"?")) return;
        var $wrap = $(this);
        $wrap.css("opacity", "0.5");
        window.PhoneCharacterAppearance.generateAvatar(name).then(function (r) {
          $wrap.css("opacity", "1");
          if (r.success) {
            yqToast("success", "Avatar của \"" + String(name).replace(/_/g, " ") + "\" đã được tạo");
            $("#phone-app-body").html(generateCharacterAppPanel());
            bindPanelButtons();
          } else {
            yqToast("error", "Tạo avatar thất bại: " + (r.error || ""));
          }
        });
      });
    /* Tạo avatar hàng loạt */
    $body
      .find(".char-app-batch-avatar")
      .off("click")
      .on("click", function (e) {
        e.preventDefault();
        e.stopPropagation();
        if (!window.PhoneCharacterAppearance) return;
        var allChars = window.PhoneCharacterAppearance.getAll();
        var names = Object.keys(allChars);
        if (names.length === 0) return;
        /* Lọc nhân vật chưa có avatar */
        var pending = [];
        for (var ni = 0; ni < names.length; ni++) {
          var av =
            typeof getCharacterAvatar === "function"
              ? getCharacterAvatar(names[ni])
              : null;
          if (!av) pending.push(names[ni]);
        }
        if (pending.length === 0) {
          yqToast("info", "Tất cả nhân vật đều đã có avatar");
          return;
        }
        if (
          !confirm(
            "Tạo avatar hàng loạt cho " +
              pending.length +
              " nhân vật?\n(Nhân vật đã có avatar sẽ bị bỏ qua)",
          )
        )
          return;
        var $btn = $(this);
        $btn
          .prop("disabled", true)
          .html('<i class="fas fa-spinner fa-spin"></i> Đang tạo...');
        var success = 0,
          fail = 0,
          idx = 0;
        function doNext() {
          if (idx >= pending.length) {
            $btn
              .prop("disabled", false)
              .html('<i class="fas fa-camera"></i> Avatar hàng loạt');
            yqToast(
              "success",
              "Tạo avatar hàng loạt hoàn tất: thành công " + success + " / thất bại " + fail,
            );
            $("#phone-app-body").html(generateCharacterAppPanel());
            bindPanelButtons();
            return;
          }
          var cn = pending[idx];
          idx++;
          $btn.html(
            '<i class="fas fa-spinner fa-spin"></i> ' +
              idx +
              "/" +
              pending.length,
          );
          window.PhoneCharacterAppearance.generateAvatar(cn)
            .then(function (r) {
              if (r.success) {
                success++;
                // Làm mới cục bộ: cập nhật ngay hiển thị avatar của nhân vật này
                var avatarUrl =
                  typeof getCharacterAvatar === "function"
                    ? getCharacterAvatar(cn)
                    : null;
                if (avatarUrl) {
                  var $wrap = $(
                    '.char-avatar-wrap[data-name="' +
                      cn.replace(/"/g, '\\"') +
                      '"]',
                  );
                  if ($wrap.length) {
                    $wrap.html(
                      '<img src="' +
                        avatarUrl +
                        '" style="width:40px;height:40px;border-radius:6px;object-fit:cover;">',
                    );
                  }
                }
              } else fail++;
              doNext();
            })
            .catch(function () {
              fail++;
              doNext();
            });
        }
        doNext();
      });

