    /* Thẻ nhân vật - đổi trang phục ban đầu */
    $body
      .find(".char-outfit-change")
      .off("click")
      .on("click", function (e) {
        e.stopPropagation();
        var charName = $(this).data("name");
        if (
          !charName ||
          !window.PhoneWardrobe ||
          !window.PhoneCharacterAppearance
        )
          return;
        var pca = window.PhoneCharacterAppearance;
        var cData = pca.get(charName);
        if (!cData) return;
        var owned = window.PhoneWardrobe.getOwnerInstances
          ? window.PhoneWardrobe.getOwnerInstances(charName)
          : [];
        var allOutfits = window.PhoneWardrobe.getAll();
        var catalogKeys = Object.keys(allOutfits);
        if (owned.length === 0 && catalogKeys.length === 0) {
          yqToast("warning", "Trong tủ đồ tạm thời chưa có trang phục");
          return;
        }
        var options = [];
        for (var oi = 0; oi < owned.length; oi++) {
          options.push({
            refId: owned[oi].id,
            label: "[Riêng] " + (owned[oi].nameCN || owned[oi].id),
          });
        }
        for (var ci = 0; ci < catalogKeys.length; ci++) {
          var ck = catalogKeys[ci];
          options.push({
            refId: ck,
            label: "[Danh mục] " + (allOutfits[ck].nameCN || ck),
          });
        }
        var optLines = options
          .map(function (x, idx) {
            var mark = cData.initialOutfit === x.refId ? " ← hiện tại" : "";
            return idx + 1 + ". " + x.label + mark;
          })
          .join("\n");
        var input = prompt(
          "Chọn trang phục ban đầu cho \"" +
            String(charName).replace(/_/g, " ") +
            "\":\n\n" +
            optLines +
            "\n\n" +
            "Nhập số thứ tự (1-" +
            options.length +
            "), nhập 0 để hủy trang phục hiện tại:",
          "",
        );
        if (input === null) return;
        input = input.trim();
        if (input === "0" || input === "") {
          window.PhoneWardrobe.assignInitialOutfit(charName, "");
          yqToast("info", "Đã hủy trang phục ban đầu của \"" + String(charName).replace(/_/g, " ") + "\"");
        } else {
          var idx = parseInt(input, 10);
          if (isNaN(idx) || idx < 1 || idx > options.length) {
            yqToast("error", "Số thứ tự không hợp lệ");
            return;
          }
          var chosenRef = options[idx - 1];
          var okAssign = window.PhoneWardrobe.assignInitialOutfit(
            charName,
            chosenRef.refId,
          );
          var fresh = pca.get(charName) || {};
          var chosenOutfit = window.PhoneWardrobe.get(fresh.initialOutfit);
          if (!okAssign) {
            yqToast("error", "Phân phối thất bại, hãy thử lại");
            return;
          }
          yqToast(
            "success",
            "\"" +
              String(charName).replace(/_/g, " ") +
              "\" -> \"" +
              (chosenOutfit
                ? chosenOutfit.nameCN || fresh.initialOutfit
                : chosenRef.label) +
              "\"",
          );
        }
        $("#phone-app-body").html(generateCharacterAppPanel());
        bindPanelButtons();
      });

    /* Tủ đồ - phân phối trang phục cho nhân vật */
    $body
      .find(".char-wardrobe-assign")
      .off("click")
      .on("click", function (e) {
        e.stopPropagation();
        var outfitId = $(this).data("outfit");
        if (!outfitId || !window.PhoneWardrobe) return;
        var outfit = window.PhoneWardrobe.get(outfitId);
        if (!outfit) return;
        var pca = window.PhoneCharacterAppearance;
        if (!pca) return;
        var allC = pca.getAll();
        var cKeys = Object.keys(allC);
        if (cKeys.length === 0) {
          yqToast("warning", "Tạm thời chưa có nhân vật cache");
          return;
        }
        var msg = "Muốn trao \"" + (outfit.nameCN || outfitId) + "\" cho ai?\n";
        msg += "(Sẽ tự động sao chép thành instance riêng của nhân vật đó, không còn dùng chung một bộ)\n\n";
        for (var _ci = 0; _ci < cKeys.length; _ci++) {
          msg += _ci + 1 + " = " + cKeys[_ci] + "\n";
        }
        msg += "\nĐể trống để hủy:";
        var chosen = prompt(msg, "");
        if (chosen === null) return;
        chosen = chosen.trim();
        if (chosen === "") return;
        var chosenIdx = parseInt(chosen, 10) - 1;
        var chosenName = "";
        if (!isNaN(chosenIdx) && chosenIdx >= 0 && chosenIdx < cKeys.length) {
          chosenName = cKeys[chosenIdx];
        } else {
          chosenName = chosen;
        }
        if (!allC[chosenName]) {
          yqToast("error", "Không tìm thấy nhân vật: " + chosen);
          return;
        }
        var okGrant = window.PhoneWardrobe.assignInitialOutfit(
          chosenName,
          outfitId,
        );
        if (!okGrant) {
          yqToast("error", "Trao thất bại");
          return;
        }
        var latest = pca.get(chosenName);
        var latestOutfit =
          latest && latest.initialOutfit
            ? window.PhoneWardrobe.get(latest.initialOutfit)
            : null;
        yqToast(
          "success",
          "Đã trao cho \"" +
            String(chosenName).replace(/_/g, " ") +
            "\": " +
            (latestOutfit
              ? latestOutfit.nameCN || latest.initialOutfit
              : outfit.nameCN || outfitId),
        );
        $("#phone-app-body").html(generateCharacterAppPanel());
        bindPanelButtons();
      });

