        var outfit = window.PhoneWardrobe.get(outfitId);
        if (!outfit) return;
        if (!confirm("Xác nhận xóa trang phục \"" + (outfit.nameCN || outfitId) + "\"?"))
          return;
        window.PhoneWardrobe.remove(outfitId);
