    /* Giám sát nano - xóa mục tiêu giám sát */
    $body
      .find(".surv-remove-btn")
      .off("click")
      .on("click", function (e) {
        e.stopPropagation();
        var name = $(this).data("name");
        if (!name) return;
        if (!confirm("Xác nhận xóa giám sát với \"" + String(name).replace(/_/g, " ") + "\"? Vật phẩm sẽ không được hoàn lại."))
          return;
        var targets = getPhoneMeta("yinqi_surveillance_targets", []);
        targets = targets.filter(function (t) {
          return (t.name || t) !== name;
        });
        setPhoneMeta("yinqi_surveillance_targets", targets);
        // Xóa dữ liệu giám sát trong MVU
        try {
          var tw = window.parent || window;
          if (tw.SillyTavern && tw.SillyTavern.getContext) {
            var ctx = tw.SillyTavern.getContext();
            if (ctx && ctx.setVariable) {
              ctx.setVariable("stat_data.hệ_thống_Ngân_Kỳ.giám_sát." + name, undefined);
              ctx.setVariable("stat_data.\u94f6\u9e92\u7cfb\u7edf.\u76d1\u63a7." + name, undefined);
            }
          }
        } catch (e2) {}
        // Xóa lịch sử mở rộng và ảnh
        var camHist = getPhoneMetaBig("cam_history", {});
        delete camHist["surv_" + name];
        setPhoneMetaBig("cam_history", camHist);
        var camImages = getPhoneMetaBig("cam_images", {});
        var _imgA = camImages["surv_" + name];
        var _imgB = camImages[name];
        if (_imgA && window.phoneImageStore)
          window.phoneImageStore.remove(_imgA);
        if (_imgB && _imgB !== _imgA && window.phoneImageStore)
          window.phoneImageStore.remove(_imgB);
        delete camImages["surv_" + name];
        delete camImages[name];
        setPhoneMetaBig("cam_images", camImages);
        yqToast("info", "Đã xóa giám sát với \"" + String(name).replace(/_/g, " ") + "\"");
        fetchLatestMvuData(true);
        $("#phone-app-body").html(generateSurveillancePanel(currentPhoneData));
        bindPanelButtons();
      });

