        if (cor <= 35)
          return "lý trí rạn nứt, dùng thuật ngữ y học phân tích tim đập nhanh nhưng càng phân tích càng rối";
        if (cor <= 55)
          return "lấy lý trí bọc dục vọng, 'chỉ thu thập dữ liệu', bề ngoài như thường nhưng nội y ngày càng táo bạo";
        if (cor <= 75)
          return "dưới vỏ bình tĩnh là dục vọng cuộn trào, ít nói nhưng câu nào cũng chí mạng, ánh mắt sau kính đã đổi";
        if (cor <= 90) return "ban ngày là sinh viên y nghiêm cẩn, ban đêm hoàn toàn khác, kiểm soát đời hai mặt rất tự nhiên";
        return "trí thức và sa đọa hòa làm một, dùng giọng bình tĩnh nhất nói lời gợi dục nhất, kính không bao giờ tháo";
