        if (cor <= 15)
          return "vẻ ngoài chị đẹp nhưng bên trong ngốc đáng yêu, xuề xòa không ranh giới, tò mò nhưng sợ tình dục";
        if (cor <= 35)
          return "mơ hồ bắt đầu có cảm giác, đổ phản ứng cơ thể cho 'chắc bị cảm', nói càng nhiều hơn";
        if (cor <= 55)
          return "vừa tự lừa vừa hưởng thụ, 'chỉ mặc đẹp hơn chút thôi mà', mơ hồ chấp nhận ngày càng nhiều";
        if (cor <= 75)
          return "sự dụ hoặc vô thức của chị đẹp chuyển thành nửa tự giác, mơ hồ thấy 'hình như cũng đâu có gì to tát'";
        if (cor <= 90)
          return "mơ hồ đồng ý mọi thứ, 'chỉ cần không bị thâm nhập thì đâu tính ngoại tình nhỉ?', ranh giới cuối";
        return "tính cách vẫn là chị đẹp mơ hồ nói nhiều ấy, chỉ quan niệm tình dục đã sa đọa, 'có gì đâu mà~'";
