        if (cor <= 15) return "mẹ vợ thanh nhã trí thức, nói năng đúng mực, ôn hòa với con rể nhưng giữ khoảng cách";
        if (cor <= 35)
          return "thỉnh thoảng chú ý ưu điểm của con rể, 'Tri Ý thật tinh mắt', sự tán thưởng chính cô cũng chưa nhận ra";
