        // [V9.6 P2 hotfix•2026-05-10] snapIsGroup chưa khai báo gây ReferenceError.
        //   Cũ: khi nối triggerSource dùng (snapIsGroup ? "group:" : "private:").
        //   Nguyên nhân: hàm chỉ snapshot snapChatId/snapChatName, thiếu currentChatIsGroup.
        //         -> tham chiếu biến chưa khai báo ném ReferenceError, bị catch ngoài (aiErr) nuốt mất.
        //         -> sau khi người chơi gửi ảnh không thấy lỗi nào, AI trả lời thất bại im lặng.
        //   Sửa: bổ sung snapshot snapIsGroup, căn theo snapChatId/Name và dùng snapshot này trong triggerSource.
        var snapIsGroup = currentChatIsGroup;
        // Đảm bảo đối tượng chat hiện tại của sender nhất quán với thời điểm gửi ảnh.
        var prevId = sender.currentFriendId;
        var prevName = sender.currentFriendName;
        var prevGroup = sender.isGroup;
        sender.setCurrentChat(snapChatId, snapChatName, snapIsGroup);
        // Gửi mô tả ảnh như một tin để kích hoạt AI trả lời.
