// renderFriendListItem / generateFriendsPanel / bindFriendSwipeEvents đã bỏ dùng.
// Giữ hàm rỗng để tránh lỗi khi còn nơi gọi cũ.
function renderFriendListItem() {
  return "";
}
function generateFriendsPanel() {
  return "";
}
function bindFriendSwipeEvents() {}

/**
 * Ánh xạ màu độ thiện cảm.
 */
function getAffectionColor(value) {
  var v = parseInt(value) || 0;
  if (v >= 80) return "#ec4899";
  if (v >= 60) return "#f43f5e";
  if (v >= 40) return "#f97316";
  if (v >= 20) return "#eab308";
  return "#9ca3af";
}

/**
 * Ánh xạ class nhịp tim theo độ thiện cảm.
 */
function getHeartBeatClass(value) {
  var v = parseInt(value) || 0;
  if (v >= 80) return "heart-beat-fast";
  if (v >= 40) return "heart-beat";
  return "heart-beat-slow";
}

/**
 * Hiển thị text HTML an toàn (tránh HTML injection nhưng giữ nguyên văn).
 */
function escapeHtml(text) {
  if (!text) return "";
  return String(text)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

/**
 * Lấy tên thật của người chơi từ context SillyTavern.
 * @returns {string} tên người chơi, mặc định "tôi"
 */
function getPlayerName() {
  try {
    var tw = window.parent || window;
    if (tw.SillyTavern && tw.SillyTavern.getContext) {
      var ctx = tw.SillyTavern.getContext();
      if (ctx && ctx.name1) return ctx.name1;
    }
  } catch (e) {}
  return "tôi";
}

/**
 * Thay {{user}} trong text bằng tên thật của người chơi.
 * @param {string} text - text chứa {{user}}
 * @returns {string} text sau khi thay.
 */
function replaceUserMacro(text) {
  if (!text) return text;
  var name = getPlayerName();
  return text.replace(/\{\{user\}\}/gi, name);
}

/**
 * Hàm khôi phục text (chuyển mã đặc biệt về ký tự bình thường).
 * Dùng để xử lý ký tự đặc biệt trong tên biến.
 */
function restoreEraText(text) {
  if (!text) return "";
  // Khôi phục __DOT__ thành . (mã tránh xung đột khi phân tích path).
  // Khôi phục __SQUOTE__ thành ' (mã tránh xung đột khi phân tích chuỗi).
  return text.replace(/__DOT__/g, ".").replace(/__SQUOTE__/g, "'");
}

