      nameEN: "casual cool black cotton t-shirt jeans campus male",
      gender: "male",
      upperBody: "black t-shirt, fitted, broad shoulders visible",
      upperBodyBack: "black t-shirt back, inverted triangle back",
      fullBody: "blue jeans, white sneakers",
      fullBodyBack: "jeans back, white sneakers",
      imageId: "",
      createdAt: 0,
