      var m = cleanedText.match(/```json\s*([\s\S]*?)```/);
      var jsonStr = m ? m[1].trim() : cleanedText.trim();
      // Nếu không bắt đầu bằng { thì tìm dấu { đầu tiên
      var start = jsonStr.indexOf("{");
      var end = jsonStr.lastIndexOf("}");
      if (start === -1 || end === -1) {
        // [V10.6] Dự phòng: dùng stack cặp ngoặc
        if (typeof extractJsonRobust === "function") {
          jsonStr = extractJsonRobust(text);
          if (!jsonStr) return null;
        } else {
          return null;
        }
      } else {
        jsonStr = jsonStr.substring(start, end + 1);
      }
      var obj = JSON.parse(jsonStr);
      // Xác thực các field bắt buộc
      var fields = [
        "nameEN",
        "facialFeatures",
        "upperBodySFW",
        "fullBodySFW",
        "upperBodyNSFW",
        "fullBodyNSFW",
      ];
      for (var i = 0; i < fields.length; i++) {
        if (!obj[fields[i]]) return null;
      }
      // Chỉ giữ field hợp lệ
      var clean = {};
      var allFields = [
        "nameCN",
        "nameEN",
        "characterTraits",
        "facialFeatures",
        "facialFeaturesBack",
        "upperBodySFW",
        "upperBodySFWBack",
        "fullBodySFW",
        "fullBodySFWBack",
        "upperBodyNSFW",
        "upperBodyNSFWBack",
        "fullBodyNSFW",
        "fullBodyNSFWBack",
        "gender",
      ];
      for (var j = 0; j < allFields.length; j++) {
        clean[allFields[j]] = obj[allFields[j]] || "";
      }
