// Áp dụng cài đặt kích thước điện thoại
function applyPhoneSize(width, height) {
  const $phoneFrame = $(".mobile-phone-frame");
  if ($phoneFrame.length === 0) {
    return;
  }

  // Đặt kích thước điện thoại
  $phoneFrame.css({
    width: width + "px",
    height: height + "px",
  });

  // Lưu vào localStorage
  try {
    localStorage.setItem("mobile-phone-width", width);
    localStorage.setItem("mobile-phone-height", height);
  } catch (e) {}

  // Sinh lại panel để cập nhật hiển thị
  const content = generateSizeSettingsPanel();
  $("#phone-app-body").html(content);

  // Bind lại sự kiện
  setTimeout(() => {
    const $appBody = $("#phone-app-body");
    $appBody.off("click.phonesize");

    $appBody.on("click.phonesize", ".phone-size-preset-btn", function (e) {
      e.preventDefault();
      const w = $(this).data("width");
      const h = $(this).data("height");
      $("#phone-width-input").val(w);
      $("#phone-height-input").val(h);
    });

    $appBody.on("click.phonesize", ".phone-size-apply-btn", function (e) {
      e.preventDefault();
      const w = parseInt($("#phone-width-input").val());
      const h = parseInt($("#phone-height-input").val());

      if (w < 320 || w > 600 || h < 500 || h > 900) {
        if (typeof toastr !== "undefined") {
          yqToast("error", "Kích thước vượt phạm vi!");
        }
        return;
      }

      applyPhoneSize(w, h);
    });

    $appBody.on("click.phonesize", ".phone-size-reset-btn", function (e) {
      e.preventDefault();
      resetPhoneSize();
    });

    // [V6.5.13 FIX•2026-04-25 qtwx-mcp-4]
    //   Ba nút phân đoạn trong panel cài đặt (hiệu năng/phương án vận hành/nhất quán) từng bị "trễ một nhịp":
    //   chọn "cân bằng" nhưng nút không sáng, bấm nút kế tiếp thì lựa chọn trước mới sáng.
    //   Nguyên nhân: setPhoneMeta() nội bộ đi qua commitPhoneMetaPatch -> setTimeout(_, 0) batch flush
    //         vào chatMetadata; còn handler sau setPhoneMeta lại gọi đồng bộ
    //         generateSettingsPanel(...). generateSettingsPanel đọc getPhoneMeta()
    //         vẫn lấy giá trị cũ -> sau render lại, trạng thái active trỏ vào nút cũ. Lần bấm sau kích hoạt setTimeout
    //         flush mới, vừa lúc giá trị lần trước được đọc ở vòng này -> biểu hiện thành "trễ một nhịp".
    //   Cách sửa: chủ động gọi _yqFlushPhoneMetaPatches() trước generateSettingsPanel,
    //         đồng bộ áp pending patch vào chatMetadata.yinqi_phone để getPhoneMeta
    //         đọc được giá trị mới ngay. saveMetadata vẫn đi batch qua debounceSavePhoneMeta, không ảnh hưởng IO.
    function _yqFlushBeforeReRenderSettings() {
      try {
        if (typeof _yqFlushPhoneMetaPatches === "function")
          _yqFlushPhoneMetaPatches();
      } catch (_eFlushSeg) {}
    }
    $appBody.on("click.phonesize", ".phone-perf-toggle-btn", function (e) {
      e.preventDefault();
      var mode = $(this).data("mode") || "normal";
      if (typeof setPhonePerfMode === "function") {
        setPhonePerfMode(mode);
      } else {
        try {
          localStorage.setItem("yinqi_phone_perf_mode", String(mode));
        } catch (_e) {}
      }
      if (typeof yqToast === "function") {
        yqToast(
          "success",
          mode === "normal"
            ? "Đã chuyển sang chế độ tiêu chuẩn"
            : mode === "ultra_save"
              ? "Đã chuyển sang chế độ siêu tiết kiệm pin"
              : "Đã chuyển sang chế độ tiết kiệm pin",
        );
      }
      _yqFlushBeforeReRenderSettings();
      $("#phone-app-body").html(generateSettingsPanel(currentPhoneData || {}));
      bindPanelButtons();
    });
    $appBody.on("click.phonesize", ".system-load-profile-btn", function (e) {
      e.preventDefault();
      var profile = String($(this).data("profile") || "balanced");
      if (["balanced", "story", "performance"].indexOf(profile) < 0) {
        profile = "balanced";
      }
      setPhoneMeta("system_load_profile_v1", profile);
      var perfMode =
        profile === "performance"
          ? "ultra_save"
          : profile === "story"
            ? "normal"
            : "normal";
      if (typeof setPhonePerfMode === "function") {
        setPhonePerfMode(perfMode);
      } else {
        setPhoneMeta("perf_mode", perfMode);
      }
      var strict = profile === "performance";
      try {
        setPhoneMeta("yinqi_consistency_guard", {
          enabled: true,
          strict: strict,
          crossChannelWindowMs: strict ? 140000 : 90000,
          sameChannelWindowMs: strict ? 45000 : 30000,
          livePriority: true,
        });
      } catch (_eProfile) {}
      yqToast(
        "success",
        profile === "performance"
          ? "Đã chuyển sang phương án ưu tiên hiệu năng"
          : profile === "story"
            ? "Đã chuyển sang phương án ưu tiên cốt truyện"
            : "Đã chuyển sang phương án cân bằng",
      );
      _yqFlushBeforeReRenderSettings();
      $("#phone-app-body").html(generateSettingsPanel(currentPhoneData || {}));
      bindPanelButtons();
    });
    $appBody.on("click.phonesize", ".consistency-mode-btn", function (e) {
      e.preventDefault();
      var mode = String($(this).data("mode") || "standard");
      var strict = mode === "strict";
      try {
        if (typeof setPhoneMeta === "function") {
          setPhoneMeta("yinqi_consistency_guard", {
            enabled: true,
            strict: strict,
            crossChannelWindowMs: strict ? 140000 : 90000,
            sameChannelWindowMs: strict ? 45000 : 30000,
            livePriority: true,
          });
        }
      } catch (_e) {}
      if (typeof yqToast === "function") {
        yqToast(
          "success",
          strict ? "Đã chuyển sang nhất quán nghiêm ngặt" : "Đã chuyển sang nhất quán tiêu chuẩn",
        );
      }
      _yqFlushBeforeReRenderSettings();
      $("#phone-app-body").html(generateSettingsPanel(currentPhoneData || {}));
      bindPanelButtons();
    });

    $appBody.on("click.phonesize", ".forum-load-more-btn", function (e) {
      e.preventDefault();
      window._forumRenderLimit = Number(window._forumRenderLimit || 18) + 12;
      renderForumPanelIfChanged._lastHtml = "";
      renderForumPanelIfChanged();
    });
  }, 100);

  // Hiển thị nhắc
  if (typeof toastr !== "undefined") {
    yqToast("success", `Kích thước điện thoại đã đặt thành ${width}×${height}`);
  }
}

// Khôi phục kích thước điện thoại mặc định
function resetPhoneSize() {
  const defaultWidth = 375;
  const defaultHeight = 667;

  applyPhoneSize(defaultWidth, defaultHeight);

  // Xóa cài đặt trong localStorage
  try {
    localStorage.removeItem("mobile-phone-width");
    localStorage.removeItem("mobile-phone-height");
  } catch (e) {}
}

// Khôi phục kích thước điện thoại đã lưu
function restorePhoneSize() {
  try {
    const savedWidth = localStorage.getItem("mobile-phone-width");
    const savedHeight = localStorage.getItem("mobile-phone-height");

    if (savedWidth && savedHeight) {
      const width = parseInt(savedWidth);
      const height = parseInt(savedHeight);

      const $phoneFrame = $(".mobile-phone-frame");
      if ($phoneFrame.length > 0) {
        $phoneFrame.css({
          width: width + "px",
          height: height + "px",
        });
      }
    }
  } catch (e) {}
}

// Chuyển trạng thái mở rộng/thu gọn của phân loại hình nền
function toggleWallpaperCategory(categoryName) {
  const container = $(
    `.wallpaper-category-images[data-category="${categoryName}"]`,
  );

  if (container.length === 0) {
    return;
  }

  // Xác định hiện đang mở rộng hay thu gọn
  if (container.is(":visible")) {
    // Thu gọn
    container.slideUp(300);
    // Cập nhật icon mũi tên
    $(`.wallpaper-category[data-category="${categoryName}"] .fa-chevron-up`)
      .removeClass("fa-chevron-up")
      .addClass("fa-chevron-down");
  } else {
    // Mở rộng
    container.slideDown(300);
    // Cập nhật icon mũi tên
    $(`.wallpaper-category[data-category="${categoryName}"] .fa-chevron-down`)
      .removeClass("fa-chevron-down")
      .addClass("fa-chevron-up");

    // Nếu là lần đầu mở rộng, tải ảnh
    if (!loadedCategories.has(categoryName)) {
      loadedCategories.add(categoryName);

      // Hiển thị animation tải
      container.html(
        '<div style="text-align: center; padding: 30px;"><i class="fas fa-circle-notch fa-spin" style="font-size: 24px; color: #9C27B0;"></i><div style="margin-top: 10px; color: #9ca3af; font-size: 13px;">Đang tải...</div></div>',
      );

      // Mô phỏng độ trễ tải, thực tế sẽ trễ vì mạng
      setTimeout(() => {
        const images = wallpaperCategories[categoryName];
        let imagesHtml =
          '<div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px;">';

        images.forEach((url, index) => {
          imagesHtml += `
                        <div class="wallpaper-item" data-wallpaper-url="${url}"
                             style="cursor: pointer; position: relative; padding-bottom: 133%; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); background: #f0f0f0;">
                            <img src="${url}"
                                 style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; object-fit: cover; transition: transform 0.2s; opacity: 0; transition: opacity 0.3s;"
                                 onload="this.style.opacity='1'"
                                 onmouseover="this.style.transform='scale(1.05)'"
                                 onmouseout="this.style.transform='scale(1)'"
                                  onerror="this.parentElement.innerHTML='<div style=\\'position:absolute;top:0;left:0;width:100%;height:100%;display:flex;align-items:center;justify-content:center;background:#f0f0f0;color:#999;font-size:11px;\\'>Tải thất bại</div>'"
                            />
                        </div>
                    `;
        });

        imagesHtml += "</div>";
        container.html(imagesHtml);
      }, 500);
    }
  }
}

function setWallpaper(imageUrl) {
  const $screen = $("#mobile-phone-overlay .mobile-phone-screen");

  if ($screen.length === 0) {
    return;
  }

  // Dùng setProperty và dấu important để ghi đè !important trong stylesheet
  const screenElement = $screen[0];
  screenElement.style.setProperty(
    "background-image",
    `url(${imageUrl})`,
    "important",
  );
  screenElement.style.setProperty("background-size", "cover", "important");
  screenElement.style.setProperty("background-position", "center", "important");
  screenElement.style.setProperty(
    "background-repeat",
    "no-repeat",
    "important",
  );

  // Lưu vào localStorage
  try {
    localStorage.setItem("moshen-phone-wallpaper", imageUrl);
  } catch (e) {}

  // Hiển thị nhắc
  if (typeof toastr !== "undefined") {
    yqToast("success", "Hình nền đã đổi");
  }
}

// Khôi phục hình nền
function restoreWallpaper() {
  try {
    var savedWallpaper = localStorage.getItem("moshen-phone-wallpaper");

    // Kiểm tra URL hình nền đã lưu có hợp lệ không, hỗ trợ URL http và data: base64
    if (
      !savedWallpaper ||
      savedWallpaper.trim() === "" ||
      (!savedWallpaper.startsWith("http") &&
        !savedWallpaper.startsWith("data:"))
    ) {
      return; // Không có hình nền hợp lệ, dùng style mặc định của CSS
    }

    var $screen = $("#mobile-phone-overlay .mobile-phone-screen");
    if ($screen.length > 0) {
      var screenElement = $screen[0];
      screenElement.style.setProperty(
        "background-image",
        "url(" + savedWallpaper + ")",
        "important",
      );
      screenElement.style.setProperty("background-size", "cover", "important");
      screenElement.style.setProperty(
        "background-position",
        "center",
        "important",
      );
      screenElement.style.setProperty(
        "background-repeat",
        "no-repeat",
        "important",
      );
    }
  } catch (e) {
    console.error("Khôi phục hình nền thất bại:", e);
  }
}

// Tải hình nền tùy chỉnh lên
function uploadCustomWallpaper(file) {
  // Kiểm tra loại file
  if (!file.type.startsWith("image/")) {
    if (typeof toastr !== "undefined") {
      yqToast("error", "Hãy chọn file ảnh");
    }
    return;
  }

  // Kiểm tra kích thước file, giới hạn 10MB
  var maxSize = 10 * 1024 * 1024;
  if (file.size > maxSize) {
    if (typeof toastr !== "undefined") {
      yqToast("error", "Kích thước file ảnh không được vượt quá 10MB");
    }
    return;
  }

  // Dùng FileReader đọc ảnh
  var reader = new FileReader();

  reader.onload = function (e) {
    var imageDataUrl = e.target.result;

    // Tạo object Image để kiểm tra và nén ảnh
    var img = new Image();
    img.onload = function () {
      // Nén ảnh để hợp localStorage, mục tiêu <500KB
      var canvas = document.createElement("canvas");
      var maxW = 800;
      var maxH = 1200;
      var w = img.width;
      var h = img.height;
      if (w > maxW || h > maxH) {
        var ratio = Math.min(maxW / w, maxH / h);
        w = Math.round(w * ratio);
        h = Math.round(h * ratio);
      }
      canvas.width = w;
      canvas.height = h;
      var ctx = canvas.getContext("2d");
      ctx.drawImage(img, 0, 0, w, h);
      var compressed = canvas.toDataURL("image/jpeg", 0.7);

      // Đặt làm hình nền
      setWallpaper(compressed);

      if (typeof toastr !== "undefined") {
        yqToast("success", "Hình nền tùy chỉnh đã tải lên");
      }

      // Reset input file
      $("#wallpaper-upload-input").val("");
    };

    img.onerror = function () {
      if (typeof toastr !== "undefined") {
        yqToast("error", "Tải ảnh thất bại, hãy chọn file ảnh hợp lệ");
      }
      $("#wallpaper-upload-input").val("");
    };

    img.src = imageDataUrl;
  };

  reader.onerror = function () {
    if (typeof toastr !== "undefined") {
      yqToast("error", "Đọc file thất bại");
    }
    $("#wallpaper-upload-input").val("");
  };

  reader.readAsDataURL(file);
}

// Reset về hình nền mặc định
