/**
 * [V6.5.5 FIX•2026-04-24] Reset mềm UI điện thoại, chỉ cache bộ nhớ, không động vào phoneMeta / IndexedDB
 *
 * Nguyên nhân: callback CHAT_CHANGED cũ gọi resetAllPhoneData(), hàm đó sẽ:
 *   1. Xóa sạch hơn 60 field chatMetadata.yinqi_phone, gồm yinqi_task_history -> mất ghi chép nhiệm vụ
 *   2. Gọi phoneImageStore.clearAll() -> xóa toàn bộ ảnh IndexedDB, như avatar/vòng bạn bè người chơi đã sinh
 *   3. Bật toast "đã xóa toàn bộ dữ liệu điện thoại" -> gây hiểu lầm cho người chơi, trong khi chỉ là đổi chat
 *
 * phoneMeta vốn độc lập theo chat, nằm trong chatMetadata.yinqi_phone;
 * khi đổi chat, chatMetadata tự đổi, không cần chủ động xóa phoneMeta.
 *
 * Nhưng để tránh cache bộ nhớ nhiễm giữa các chat, ví dụ _worldEventsCache vẫn giữ dữ liệu chat cũ,
 * cần dọn các cache toàn cục thuần bộ nhớ này.
 *
 * Mọi thao tác nặng như xóa ảnh / xóa phoneMeta / bật toast vẫn dành cho resetAllPhoneData, kích hoạt thủ công.
 */
function resetMobileUiSoftly() {
  try {
    try {
      window._worldEventsCache = null;
    } catch (e) {}
    try {
      if (window.phoneForumManager) {
        window.phoneForumManager.forumData = null;
        window.phoneForumManager.commentedPosts = [];
        window.phoneForumManager.userPosts = [];
      }
    } catch (e) {}
    try {
      if (typeof yqIdbResetCache === "function") yqIdbResetCache();
      if (typeof _yqIdbPreloadCache === "function")
        setTimeout(_yqIdbPreloadCache, 500);
    } catch (e) {}
    try {
      var tw = window.parent || window;
      if (tw.SillyTavern && tw.SillyTavern.getContext) {
        var ctx = tw.SillyTavern.getContext();
        if (ctx && typeof ctx.setExtensionPrompt === "function") {
          ctx.setExtensionPrompt("yinqi-npc-messages", "", 1, 0);
        }
      }
    } catch (e) {}
    try {
      console.log("[Reset mềm UI điện thoại] Đã xóa cache bộ nhớ + tải lại cache IDB");
    } catch (_) {}
  } catch (e) {
    try {
      console.warn("[Reset mềm UI điện thoại] Bất thường:", e && e.message);
    } catch (_) {}
  }
}
try {
  window.resetMobileUiSoftly = resetMobileUiSoftly;
} catch (_) {}

function _renderPhonePanelKeyIsActive(panelKey) {
  try {
    var p =
      typeof currentPanel !== "undefined" ? currentPanel : window.currentPanel;
    if (!p) return false;
    if (panelKey === "world-events") return p === "world-events";
    if (panelKey === "surveillance") return p === "surveillance";
    if (panelKey === "world") return p === "world";
  } catch (e) {}
  return false;
}

function renderPhonePanelIfChanged(panelKey, html) {
  if (!html) return;
  if (!renderPhonePanelIfChanged._cache) renderPhonePanelIfChanged._cache = {};
  var active = _renderPhonePanelKeyIsActive(panelKey);
  /* Chỉ ghi DOM khi người dùng đang ở App đó; nếu không thì chỉ cập nhật cache để tránh bị thay nhầm từ giao diện tin nhắn */
  if (renderPhonePanelIfChanged._cache[panelKey] === html) {
    if (active) return;
    return;
  }
  renderPhonePanelIfChanged._cache[panelKey] = html;
  if (!active) return;

  var $body = $("#phone-app-body");
  try {
    window._yqPerfStats = window._yqPerfStats || {};
    window._yqPerfStats.phonePanelFullRenders =
      (window._yqPerfStats.phonePanelFullRenders || 0) + 1;
  } catch (_eStat) {}
  var prevScroll = $body.length ? $body.scrollTop() : 0;
  var lastKey = renderPhonePanelIfChanged._lastPanelKey;
  var panelSwitched = lastKey !== undefined && lastKey !== panelKey;
  renderPhonePanelIfChanged._lastPanelKey = panelKey;
  $body.html(html);
  bindPanelButtons();
  if (!panelSwitched && prevScroll > 0) {
    var el = $body[0];
    requestAnimationFrame(function () {
      requestAnimationFrame(function () {
        if (!el || !el.isConnected) return;
        var max = el.scrollHeight - el.clientHeight;
        el.scrollTop = Math.min(prevScroll, Math.max(0, max));
      });
    });
  }
}

// ==================== Xuất/nhập dữ liệu ====================

/**
 * Xuất dữ liệu điện thoại thành file JSON
 * @param {boolean} includeImages - có bao gồm ảnh không, file kèm ảnh sẽ rất lớn
 */
function phoneExportData(includeImages) {
  try {
    yqToast("info", "Đang thu thập dữ liệu...", "📦 Xuất");
    var exportObj = {
      _version: "14",
      _exportTime: new Date().toISOString(),
      _type: "full",
    };
    // Thu thập mọi key phoneMeta
    var metaKeys = [
      "known_friends",
      "yinqi_friend_alias",
      "yinqi_friend_alias_norm",
      "yinqi_friend_meta",
      "yinqi_friend_graph_version",
      "yinqi_friend_ui_migrate_v1",
      "friend_requests",
      "friend_request_history",
      "blocked_friends",
      "pinned_friends",
      "groups",
      "group_invites",
      "social_seed_state",
      "yinqi_social_config",
      "moments",
      "hidden_friends",
      "forum_data",
      "forum_commented",
      "forum_user_posts",
      "cam_history",
      "npc_messages",
      "chat_history",
      "unreads",
      "moments_unread",
      "world_events_unread",
      "forum_unread",
      "image_index",
      "cam_tag_cache",
      "cam_images",
      "imageGen_settings",
      "live_rooms",
      "live_unread",
      "live_interactions",
      "chat_avatars",
      "ai_awareness_settings",
      "ai_awareness_v2",
      "ui_theme_config_v1",
      "character_appearances",
      "char_appearance_enabled",
      "phone_wardrobe",
      "phone_wardrobe_instances",
      "phone_wardrobe_schema_version",
      "phone_wardrobe_legacy_backup",
      "phone_wardrobe_diag_stats",
      "forum_nickname",
      "live_nickname",
      "phone_story_live_events",
      "forum_summary_user",
      "forum_summary_commented",
      "live_summary",
      "operation_log",
      "perf_mode",
      "perf_cache",
      "yinqi_char_timeline",
      "yinqi_char_facts",
      "yinqi_char_runtime_state",
      "yinqi_consistency_guard",
      "yinqi_char_channel_lock",
      "yinqi_link_rules",
      "yinqi_cross_feed",
      "yinqi_task_history",
      "yinqi_surveillance_targets",
      "yinqi_plot_task",
      "yinqi_outposts",
      "yinqi_forum_tasks",
    ];
    exportObj.phoneMeta = {};
    for (var i = 0; i < metaKeys.length; i++) {
      exportObj.phoneMeta[metaKeys[i]] = getPhoneMeta(metaKeys[i], null);
    }
    // Thu thập mục localStorage
    exportObj.localStorage = {};
    for (var j = 0; j < localStorage.length; j++) {
      var k = localStorage.key(j);
      if (
        k &&
        (k.startsWith("yinqi-") ||
          k.startsWith("moshen-") ||
          k === "forum_auto_generate" ||
          k.startsWith("mobile-phone-") ||
          k.startsWith("mobile-last-") ||
          k.startsWith("mobile-trigger-btn-"))
      ) {
        exportObj.localStorage[k] = localStorage.getItem(k);
      }
    }
    if (!includeImages) {
      _triggerDownload(exportObj, "phone-data-no-img");
      return;
    }
    // Kèm ảnh: đọc toàn bộ ảnh từ IndexedDB
    var imgIndex = getPhoneMetaBig("image_index", []);
    var imgIds = imgIndex.map(function (e) {
      return e.id;
    });
    // Cũng thu thập imageId trong cam_images
    var camImgs = getPhoneMetaBig("cam_images", {});
    var camVals = Object.values(camImgs);
    for (var ci = 0; ci < camVals.length; ci++) {
      if (
        camVals[ci] &&
        typeof camVals[ci] === "string" &&
        camVals[ci].indexOf("data:") !== 0 &&
        imgIds.indexOf(camVals[ci]) === -1
      ) {
        imgIds.push(camVals[ci]);
      }
    }
    if (imgIds.length === 0 || !window.phoneImageStore) {
      _triggerDownload(exportObj, "phone-data-full");
      return;
    }
    // Ghi ảnh dạng streaming, tải từng ảnh rồi ghi ngay vào chunk và giải phóng bộ nhớ
    var total = imgIds.length;
    var loaded = 0;
    var failed = 0;
    yqToast("info", "Đang xuất " + total + " ảnh...", "📦 Xuất");
    var headerJson = JSON.stringify(exportObj);
    // Chèn ,"images":{ trước dấu } cuối
    var chunks = [headerJson.slice(0, -1) + ',"images":{'];
    headerJson = null;
    exportObj = null; // Giải phóng tham chiếu
    var isFirst = true;
    var doLoad = function (idx) {
      if (idx >= total) {
        chunks.push("}}");
        var blob = new Blob(chunks, { type: "application/json" });
        chunks = null;
        _triggerDownloadBlob(blob, "phone-data-full");
        if (failed > 0)
          yqToast("warning", failed + " ảnh tải thất bại đã được bỏ qua", "📦 Xuất");
        return;
      }
      window.phoneImageStore
        .loadAsync(imgIds[idx])
        .then(function (data) {
          if (data) {
            var prefix = isFirst ? "" : ",";
            chunks.push(
              prefix + JSON.stringify(imgIds[idx]) + ":" + JSON.stringify(data),
            );
            isFirst = false;
            delete window.phoneImageStore._cache[imgIds[idx]];
          } else {
            failed++;
          }
          loaded++;
          if (loaded % 10 === 0)
            yqToast(
              "info",
              "Đã xử lý " + loaded + "/" + total + " ảnh...",
              "📦 Xuất",
            );
          setTimeout(function () {
            doLoad(idx + 1);
          }, 0);
        })
        .catch(function () {
          failed++;
          loaded++;
          setTimeout(function () {
            doLoad(idx + 1);
          }, 0);
        });
    };
    doLoad(0);
  } catch (e) {
    console.error("[Xuất] Thất bại:", e);
    yqToast("error", "Xuất thất bại: " + e.message);
  }
}

/**
 * Chỉ xuất dữ liệu album (image_index + ảnh)
 * v14: ghi streaming, tải từng ảnh rồi ghi ngay vào Blob chunk và giải phóng bộ nhớ, tránh OOM khi nhiều ảnh
 */
function phoneExportGallery() {
  try {
    yqToast("info", "Đang thu thập dữ liệu album...", "💾 Xuất album");
    var imageIndex = getPhoneMetaBig("image_index", []);
    if (imageIndex.length === 0) {
      yqToast("warning", "Album rỗng, không cần xuất");
      return;
    }
    var imgIds = imageIndex.map(function (e) {
      return e.id;
    });
    // Cũng bao gồm ảnh được cam_images tham chiếu
    var camImgs = getPhoneMetaBig("cam_images", {});
    var camVals = Object.values(camImgs);
    for (var ci = 0; ci < camVals.length; ci++) {
      if (
        camVals[ci] &&
        typeof camVals[ci] === "string" &&
        camVals[ci].indexOf("data:") !== 0 &&
        imgIds.indexOf(camVals[ci]) === -1
      ) {
        imgIds.push(camVals[ci]);
      }
    }
    // Dựng JSON đầu, không gồm images, rồi nối images dạng streaming
    var header = {
      _version: "14",
      _exportTime: new Date().toISOString(),
      _type: "gallery",
      image_index: imageIndex,
      cam_images: camImgs,
    };
    if (!window.phoneImageStore || imgIds.length === 0) {
      header.images = {};
      _triggerDownload(header, "phone-gallery");
      return;
    }
    var total = imgIds.length;
    var loaded = 0;
    var failed = 0;
    yqToast("info", "Đang xuất " + total + " ảnh...", "💾 Xuất album");
    // Ghi streaming: ghi header trước, bỏ } cuối, thêm từng ảnh rồi đóng lại cuối cùng
    var headerJson = JSON.stringify(header);
    // Chèn ,"images":{ trước dấu } cuối
    var chunks = [headerJson.slice(0, -1) + ',"images":{'];
    var isFirst = true;
    var doLoad = function (idx) {
      if (idx >= total) {
        // Đóng object images và object gốc
        chunks.push("}}");
        var blob = new Blob(chunks, { type: "application/json" });
        // Giải phóng tham chiếu chunks
        chunks = null;
        _triggerDownloadBlob(blob, "phone-gallery");
        if (failed > 0)
          yqToast("warning", failed + " ảnh tải thất bại đã được bỏ qua", "💾 Xuất album");
        return;
      }
      window.phoneImageStore
        .loadAsync(imgIds[idx])
        .then(function (data) {
          if (data) {
            var prefix = isFirst ? "" : ",";
            chunks.push(
              prefix + JSON.stringify(imgIds[idx]) + ":" + JSON.stringify(data),
            );
            isFirst = false;
            // Xóa ảnh đã ghi khỏi cache bộ nhớ để giải phóng bộ nhớ
            delete window.phoneImageStore._cache[imgIds[idx]];
          } else {
            failed++;
          }
          loaded++;
          if (loaded % 10 === 0)
            yqToast(
              "info",
              "Đã xử lý " + loaded + "/" + total + " ảnh...",
              "💾 Xuất album",
            );
          // Nhường main thread, tránh block UI quá lâu
          setTimeout(function () {
            doLoad(idx + 1);
          }, 0);
        })
        .catch(function () {
          failed++;
          loaded++;
          setTimeout(function () {
            doLoad(idx + 1);
          }, 0);
        });
    };
    doLoad(0);
  } catch (e) {
    console.error("[Xuất album] Thất bại:", e);
    yqToast("error", "Xuất album thất bại: " + e.message);
  }
}

/**
 * Kích hoạt trình duyệt tải file JSON, từ object
 */
function _triggerDownload(obj, prefix) {
  try {
    var json = JSON.stringify(obj);
    var blob = new Blob([json], { type: "application/json" });
    json = null; // Giải phóng bộ nhớ chuỗi
    _triggerDownloadBlob(blob, prefix);
  } catch (e) {
    console.error("[Tải xuống] Thất bại:", e);
    yqToast("error", "Tải xuống thất bại: " + e.message);
  }
}

/**
 * Kích hoạt trình duyệt tải xuống, từ Blob, dùng cho xuất streaming
 */
function _triggerDownloadBlob(blob, prefix) {
  try {
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    var ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
    a.href = url;
    a.download = prefix + "_" + ts + ".json";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(function () {
      URL.revokeObjectURL(url);
    }, 1000);
    var sizeMB = (blob.size / 1024 / 1024).toFixed(1);
    yqToast("success", "Xuất hoàn tất (" + sizeMB + "MB)", "📦 Xuất");
  } catch (e) {
    console.error("[Tải xuống] Thất bại:", e);
    yqToast("error", "Tải xuống thất bại: " + e.message);
  }
}

/**
 * Nhập dữ liệu điện thoại, nhập đầy đủ
 * @param {string} jsonStr - chuỗi JSON
 */
function phoneImportData(jsonStr) {
  try {
    var data = JSON.parse(jsonStr);
    if (!data._type || !data._version) {
      yqToast("error", "File xuất không hợp lệ");
      return;
    }
    if (data._type === "gallery") {
      // Dữ liệu gallery đã parse thì truyền trực tiếp object, tránh parse lần hai
      _doImportGalleryParsed(data);
      return;
    }
    if (
      !confirm(
        "Xác nhận nhập dữ liệu điện thoại?\nToàn bộ dữ liệu điện thoại hiện tại sẽ bị ghi đè.\n\nThời gian xuất: " +
          (data._exportTime || "không rõ"),
      )
    )
      return;
    yqToast("info", "Đang nhập...", "📥 Nhập");
    // Khôi phục phoneMeta
    if (data.phoneMeta) {
      var keys = Object.keys(data.phoneMeta);
      for (var i = 0; i < keys.length; i++) {
        if (
          data.phoneMeta[keys[i]] !== null &&
          data.phoneMeta[keys[i]] !== undefined
        ) {
          setPhoneMeta(keys[i], data.phoneMeta[keys[i]]);
        }
      }
      debounceSavePhoneMeta();
    }
    // Khôi phục localStorage
    if (data.localStorage) {
      var lsKeys = Object.keys(data.localStorage);
      for (var j = 0; j < lsKeys.length; j++) {
        localStorage.setItem(lsKeys[j], data.localStorage[lsKeys[j]]);
      }
    }
    // Khôi phục ảnh vào IndexedDB
    if (data.images && window.phoneImageStore) {
      var imgKeys = Object.keys(data.images);
      var restored = 0;
      var doRestore = function (idx) {
        if (idx >= imgKeys.length) {
          data.images = null;
          yqToast(
            "success",
            "Nhập hoàn tất! Đã khôi phục " + restored + " ảnh\nHãy refresh giao diện điện thoại để xem",
            "📥 Nhập",
          );
          // Refresh panel hiện tại
          try {
            if (currentPanel) {
              $("#phone-app-body").html(generateSizeSettingsPanel());
              bindPanelButtons();
            }
          } catch (e2) {}
          return;
        }
        var id = imgKeys[idx];
        var imgData = data.images[id];
        delete data.images[id]; // Sau khi ghi thì giải phóng bộ nhớ
        if (!imgData) {
          doRestore(idx + 1);
          return;
        }
        window.phoneImageStore._cache[id] = imgData;
        window.phoneImageStore._dbPut(id, imgData).then(function () {
          restored++;
          if (restored % 20 === 0)
            yqToast(
              "info",
              "Đã khôi phục " + restored + "/" + imgKeys.length + " ảnh...",
              "📥 Nhập",
            );
          setTimeout(function () {
            doRestore(idx + 1);
          }, 0);
        });
      };
      doRestore(0);
    } else {
      yqToast("success", "Nhập hoàn tất! Hãy refresh giao diện điện thoại để xem", "📥 Nhập");
      try {
        if (currentPanel) {
          $("#phone-app-body").html(generateSizeSettingsPanel());
          bindPanelButtons();
        }
      } catch (e2) {}
    }
  } catch (e) {
    console.error("[Nhập] Thất bại:", e);
    yqToast("error", "Nhập thất bại: " + e.message);
  }
}

/**
 * Nhập dữ liệu album, chế độ gộp, không ghi đè dữ liệu hiện có
 * v14: hỗ trợ parse streaming file lớn, trích header trước (image_index/cam_images), rồi trích từng images
 * @param {string|Blob|File} input - chuỗi JSON hoặc object File/Blob
 */
function phoneImportGallery(input) {
  try {
    // Nếu input là string và không quá lớn (<50MB), parse JSON trực tiếp
    if (typeof input === "string" && input.length < 50 * 1024 * 1024) {
      _doImportGalleryParsed(JSON.parse(input));
      return;
    }
    // File lớn hoặc Blob/File: parse streaming
    var blob = typeof input === "string" ? new Blob([input]) : input;
    yqToast("info", "Đang phân tích file lớn...", "📥 Nhập album");
    // Dùng Response.json() hiệu quả hơn JSON.parse, streaming native của trình duyệt
    new Response(blob)
      .json()
      .then(function (data) {
        _doImportGalleryParsed(data);
      })
      .catch(function (e) {
        console.error("[Nhập album] Phân tích JSON thất bại, thử sửa:", e);
        // Có thể file bị cắt ở cuối, thử đọc text rồi sửa thủ công
        new Response(blob)
          .text()
          .then(function (text) {
            // Kiểm tra cuối file có thiếu ngoặc đóng không
            var trimmed = text.trimEnd();
            if (
              trimmed.charAt(trimmed.length - 1) !== "}" &&
              trimmed.indexOf('"images"') !== -1
            ) {
              // Thử bổ sung ngoặc đóng
              var fixed = trimmed + "}}";
              try {
                var data2 = JSON.parse(fixed);
                yqToast("warning", "Cuối file không hoàn chỉnh, đã tự sửa", "📥 Nhập album");
                _doImportGalleryParsed(data2);
                return;
              } catch (e2) {}
            }
            yqToast(
              "error",
              "Format file album bị hỏng, không thể nhập: " + e.message,
              "📥 Nhập album",
            );
          })
          .catch(function () {
            yqToast("error", "Đọc file thất bại", "📥 Nhập album");
          });
      });
  } catch (e) {
    console.error("[Nhập album] Thất bại:", e);
    yqToast("error", "Nhập album thất bại: " + e.message);
  }
}

/**
 * Thực thi nhập album, object dữ liệu đã parse
 */
function _doImportGalleryParsed(data) {
  try {
    if (!data || !data.image_index) {
      yqToast("error", "File xuất album không hợp lệ");
      return;
    }
    var newCount = data.image_index.length;
    if (
      !confirm(
        "Xác nhận nhập album?\nSẽ gộp " +
          newCount +
          " bản ghi ảnh vào album hiện tại.\nẢnh có cùng ID đã tồn tại sẽ không nhập trùng.",
      )
    )
      return;
    yqToast("info", "Đang nhập album...", "📥 Nhập album");
    // Gộp image_index, khử trùng lặp
    var currentIdx = getPhoneMetaBig("image_index", []);
    var existingIds = {};
    for (var i = 0; i < currentIdx.length; i++)
      existingIds[currentIdx[i].id] = true;
    var added = 0;
    for (var j = 0; j < data.image_index.length; j++) {
      if (!existingIds[data.image_index[j].id]) {
        currentIdx.push(data.image_index[j]);
        added++;
      }
    }
    // Sắp xếp theo timestamp, mới ở trước
    currentIdx.sort(function (a, b) {
      return (b.timestamp || 0) - (a.timestamp || 0);
    });
    setPhoneMetaBig("image_index", currentIdx);
    // Gộp cam_images
    if (data.cam_images) {
      var curCam = getPhoneMetaBig("cam_images", {});
      var camKeys = Object.keys(data.cam_images);
      for (var ck = 0; ck < camKeys.length; ck++) {
        if (!curCam[camKeys[ck]])
          curCam[camKeys[ck]] = data.cam_images[camKeys[ck]];
      }
      setPhoneMetaBig("cam_images", curCam);
    }
    debounceSavePhoneMeta();
    // Khôi phục ảnh vào IndexedDB, ghi từng ảnh rồi giải phóng bộ nhớ
    if (data.images && window.phoneImageStore) {
      var imgKeys = Object.keys(data.images);
      var restored = 0;
      var doRestore = function (idx) {
        if (idx >= imgKeys.length) {
          // Giải phóng tham chiếu images để GC thu hồi
          data.images = null;
          data = null;
          yqToast(
            "success",
            "Nhập album hoàn tất! Đã thêm " +
              added +
              " bản ghi, khôi phục " +
              restored +
              " ảnh",
            "📥 Nhập album",
          );
          return;
        }
        var id = imgKeys[idx];
        var imgData = data.images[id];
        // Sau khi ghi thì xóa ngay khỏi data để giải phóng bộ nhớ
        delete data.images[id];
        if (!imgData) {
          doRestore(idx + 1);
          return;
        }
        window.phoneImageStore._cache[id] = imgData;
        window.phoneImageStore._dbPut(id, imgData).then(function () {
          restored++;
          if (restored % 20 === 0)
            yqToast(
              "info",
              "Đã khôi phục " + restored + "/" + imgKeys.length + " ảnh...",
              "📥 Nhập album",
            );
          // Nhường main thread
          setTimeout(function () {
            doRestore(idx + 1);
          }, 0);
        });
      };
      doRestore(0);
    } else {
      yqToast(
        "success",
        "Nhập index album hoàn tất! Đã thêm " + added + " bản ghi (không có dữ liệu ảnh)",
        "📥 Nhập album",
      );
    }
  } catch (e) {
    console.error("[Nhập album] Thất bại:", e);
    yqToast("error", "Nhập album thất bại: " + e.message);
  }
}

/**
 * Dựng lại index album: quét mọi ảnh còn sót trong IndexedDB, sinh lại image_index
 * Dùng để khôi phục quyền truy cập ảnh lẻ sau khi xóa chat
 */
function phoneRebuildImageIndex() {
  if (!window.phoneImageStore) {
    yqToast("error", "Kho ảnh chưa khởi tạo");
    return;
  }
  yqToast("info", "Đang quét database ảnh cục bộ...", "🔄 Dựng lại index");
  window.phoneImageStore.getAllKeys().then(function (allKeys) {
    if (!allKeys || allKeys.length === 0) {
      yqToast("warning", "Không tìm thấy ảnh nào trong database cục bộ");
      return;
    }
    // Lấy index hiện tại, tìm ID đã có
    var currentIdx = getPhoneMetaBig("image_index", []);
    var existingIds = {};
    for (var i = 0; i < currentIdx.length; i++)
      existingIds[currentIdx[i].id] = true;
    // Tìm ảnh lẻ, có trong DB nhưng không có trong index
    var orphanKeys = [];
    for (var j = 0; j < allKeys.length; j++) {
      if (!existingIds[allKeys[j]]) orphanKeys.push(allKeys[j]);
    }
    if (orphanKeys.length === 0) {
      yqToast(
        "info",
        "Mọi ảnh đều đã có index, không cần dựng lại (tổng " + currentIdx.length + " mục)",
      );
      return;
    }
    // Tạo bản ghi index cho ảnh lẻ
    var added = 0;
    for (var k = 0; k < orphanKeys.length; k++) {
      var id = orphanKeys[k];
      var source = "recovered";
      var tag = "khôi phục";
      if (id.indexOf("cam-") === 0) {
        source = "surveillance";
        tag = "giám sát";
      }
      currentIdx.push({
        id: id,
        source: source,
        location: "",
        description: "(khôi phục bằng dựng lại index)",
        time: new Date().toLocaleString(),
        tag: tag,
        size: { w: 1024, h: 1024 },
        timestamp: Date.now() - (orphanKeys.length - k),
        hasImage: true,
      });
      added++;
    }
    // Sắp xếp theo timestamp
    currentIdx.sort(function (a, b) {
      return (b.timestamp || 0) - (a.timestamp || 0);
    });
    setPhoneMetaBig("image_index", currentIdx);
    debounceSavePhoneMeta();
    // Preload vào cache bộ nhớ
    window.phoneImageStore.preload(orphanKeys);
    yqToast(
      "success",
      "Dựng lại hoàn tất! Đã khôi phục " +
        added +
        " ảnh lẻ\nIndex cũ giữ lại " +
        Object.keys(existingIds).length +
        " mục",
      "🔄 Dựng lại index",
    );
  });
}

// Expose ra window
window.phoneExportData = phoneExportData;
window.phoneExportGallery = phoneExportGallery;
window.phoneImportData = phoneImportData;
window.phoneImportGallery = phoneImportGallery;
window.phoneRebuildImageIndex = phoneRebuildImageIndex;

/**
 * Lắng nghe sự kiện đổi character card, tự reset dữ liệu điện thoại
 * Lưu ý: CHAT_CHANGED sẽ bị kích hoạt bởi nhiều thao tác (áp regex, refresh tin nhắn...)
 * nên phải so sánh chatId để xác định thật sự đổi character card/chat, tránh xóa nhầm dữ liệu
 */
var _lastKnownChatId = null;
var _yqChatChangeListenerSetup = false;
function setupCharacterChangeListener() {
  // [V10.11 FIX•2026-05-18] Guard idempotent, tránh subscribe trùng sự kiện CHAT_CHANGED, vì mỗi lần openMobilePhone đều gọi hàm này
  if (_yqChatChangeListenerSetup) return;
  _yqChatChangeListenerSetup = true;
  try {
    var tw = window.parent || window;
    if (tw.SillyTavern && tw.SillyTavern.getContext) {
      var ctx = tw.SillyTavern.getContext();
      if (ctx && ctx.eventSource && ctx.event_types) {
        // Ghi chatId ban đầu
        // [V10.11 FIX] tw.SillyTavern.getCurrentChatId có thể không tồn tại trong một số phiên bản ST/ngữ cảnh iframe, dùng getContext().chatId dự phòng
        try {
          if (typeof tw.SillyTavern.getCurrentChatId === "function") {
            _lastKnownChatId = tw.SillyTavern.getCurrentChatId() || null;
          } else if (typeof tw.SillyTavern.getContext === "function") {
            var _initCtx = tw.SillyTavern.getContext();
            _lastKnownChatId = (_initCtx && _initCtx.chatId) || null;
          }
        } catch (e) {
          _lastKnownChatId = null;
        }
        // Lắng nghe đổi character card/chat, chỉ reset khi chatId thật sự đổi
        // [V6.5.1 FIX•2026-04-24] Fallback tên sự kiện, cùng mẫu sửa với panel hệ thống Ngân Kỳ V6.5 B
        //   - Code cũ `if (ctx.event_types.CHAT_CHANGED)` có thể undefined ở một số bản ST.
        //   - Khi đó toàn bộ subscribe CHAT_CHANGED bị bỏ qua im lặng -> chat mới chat_avatars={} -> `yqEnsureDefaultAvatars` không bao giờ chạy.
        //     Người chơi thấy "chat mới không hiện avatar tích hợp".
        //   - Fix: dùng `|| "chat_changed"` fallback về literal snake_case thực tế ST phát ra.
        var _ccEvt = ctx.event_types.CHAT_CHANGED || "chat_changed";
        ctx.eventSource.on(_ccEvt, function (newChatId) {
          // Lần đầu nhận sự kiện chỉ ghi chatId, không reset, đây là lần tải đầu sau refresh trang
          if (!_lastKnownChatId) {
            _lastKnownChatId = newChatId;
            // [V10.11 FIX•2026-05-18] Lần tải đầu cũng phải reset + preload cache IDB.
            //   Nguyên nhân: yqIdbMigrateFromPhoneMeta kích hoạt bằng timer 500ms; lúc đó getCurrentChatId() có thể chưa sẵn sàng,
            //         preload dùng chatId sai hoặc "global", làm _yqIdbCache rỗng vĩnh viễn,
            //         setPhoneMetaBig về sau dùng fallback rỗng ghi đè dữ liệu thật -> mất dữ liệu.
            //   Cách sửa: khi CHAT_CHANGED thật sự kích hoạt, lúc này chatId chắc chắn đúng, ép reset+preload.
            try {
              if (typeof yqIdbResetCache === "function") yqIdbResetCache();
              if (typeof _yqIdbPreloadCache === "function") {
                setTimeout(_yqIdbPreloadCache, 50);
              }
            } catch (_eIdbFirst) {}
            // [V6.5.1 FIX•2026-04-24] Sau refresh trang, lần tải đầu cũng bổ sung avatar.
            //   - Code cũ chỉ bổ sung khi "chatId thật sự đổi"; nhưng sau F5, chat_avatars của phiên mới có thể rỗng.
            //   - initializeMobilePhone() tuy cũng gọi một lần, nhưng lúc đó chatMetadata có thể chưa sẵn sàng.
            //   - Delay 300ms rồi bổ sung lần nữa, đảm bảo sau khi chatMetadata đổi xong, chat_avatars được điền đầy.
            setTimeout(function () {
              try {
                if (typeof window.yqEnsureDefaultAvatars === "function") {
                  window.yqEnsureDefaultAvatars();
                }
              } catch (_eFirstLoad) {}
            }, 300);
            return;
          }
          // Nếu chatId giống nhau thì bỏ qua, vì áp regex/refresh tin nhắn cũng kích hoạt sự kiện này
          if (newChatId && _lastKnownChatId === newChatId) {
            return;
          }
          console.log(
            "[Dữ liệu điện thoại] Đổi chat: " + _lastKnownChatId + " -> " + newChatId,
          );
          _lastKnownChatId = newChatId;
          // [V6.5.5 FIX•2026-04-24] Chuyển sang reset mềm, không xóa phoneMeta / ảnh IndexedDB của chat hiện tại
          //   resetAllPhoneData cũ sẽ xóa lịch sử nhiệm vụ + mọi ảnh IndexedDB + bật toast gây hiểu lầm
          //   phoneMeta độc lập theo chat, khi đổi chat chatMetadata tự đổi, không cần chủ động xóa
          resetMobileUiSoftly();
          // [V6.1 FIX•2026-04-22] Sau khi đổi chat, bổ sung avatar mặc định tích hợp
          //   - Chat mới có chat_avatars = {} hoặc thiếu -> khi render avatar rỗng -> người chơi thấy "avatar biến mất"
          //   - Gọi yqEnsureDefaultAvatars(), idempotent fixedId, không chiếm IDB trùng
          //   - Delay 150ms để chờ chatMetadata đổi xong rồi mới ghi
          setTimeout(function () {
            try {
              if (typeof window.yqEnsureDefaultAvatars === "function") {
                window.yqEnsureDefaultAvatars();
              }
              if (typeof window._yqFlushPhoneMetaPatches === "function") {
                window._yqFlushPhoneMetaPatches();
              }
            } catch (_eCh) {}
          }, 150);
        });
        // Lắng nghe xóa character card, cũng dùng fallback
        var _cdEvt = ctx.event_types.CHARACTER_DELETED || "character_deleted";
        ctx.eventSource.on(_cdEvt, function () {
          console.log("[Dữ liệu điện thoại] Phát hiện character card bị xóa, reset dữ liệu điện thoại");
          _lastKnownChatId = null;
          resetAllPhoneData();
        });
        console.log("[Dữ liệu điện thoại] Đã thiết lập listener đổi/xóa character card");
      }
    }
  } catch (e) {
    console.warn("[Dữ liệu điện thoại] Thiết lập listener character card thất bại:", e);
  }
}

function cleanupMobilePhone() {
  // Xóa timer thời gian điện thoại
  if (_phoneTimeIntervalId) {
    clearInterval(_phoneTimeIntervalId);
    _phoneTimeIntervalId = null;
  }

  // Dừng cơ chế refresh, gồm polling, refresh chat...
  if (typeof stopRefreshMechanism === "function") stopRefreshMechanism();

  // Dừng tự sinh livestream
  if (typeof stopLiveAutoGeneration === "function") stopLiveAutoGeneration();

  // Dự phòng: unregister mọi task phoneScheduler, như chat:autoRefresh, autogen:poll...
  try {
    if (typeof window.phoneUnscheduleAllTasks === "function") {
      window.phoneUnscheduleAllTasks();
    }
  } catch (_schErr) {}

  // Gỡ listener kéo nút kích hoạt
  $("#mobile-trigger-btn").off("mousedown touchstart click");

  // Gỡ listener resize cửa sổ
  $(window).off("resize.mobilePhone");

  // Gỡ event delegation cấp document, bind trong 03_events.js
  $(document).off(
    "click.phoneDoc change.phoneDoc dblclick.phoneDoc keydown.phoneDoc keydown.phoneEsc",
  );

  // Gỡ listener nút forum ở capture phase, được 02_init.js bơm vào
  try {
    if (window.__yqCaptureClickRef) {
      document.removeEventListener("click", window.__yqCaptureClickRef, true);
      window.__yqCaptureClickRef = null;
    }
  } catch (_e) {}
  $("body").off(
    "click.appIcon click.createGroupBtn click.clearEvidenceBtn click.momentsEntry click.msgTab click.forumPostItem click.worldEventsEntry click.contactItem click.messageImage",
  );

  // Gỡ listener kéo giao diện điện thoại, native event
  const dragHandle = document.getElementById("phone-drag-handle");
  if (dragHandle) {
    dragHandle.removeEventListener("pointerdown", handlePhoneDragStart);
    dragHandle.removeEventListener("pointermove", handlePhoneDragMove);
    dragHandle.removeEventListener("pointerup", handlePhoneDragEnd);
    dragHandle.removeEventListener("pointercancel", handlePhoneDragEnd);
  }

  // Reset trạng thái kéo
  isDragging = false;
  hasMoved = false;
  isPhoneDragging = false;

  // Reset trạng thái ghim lên trên
  isPinned = false;

  $("#mobile-trigger-btn").remove();
  $("#mobile-phone-overlay").remove();
  $("#mobile-phone-styles").remove();
}

// ==================== Kiểm tra trạng thái sinh tầng chính ====================
/**
 * Chờ AI tầng chính sinh xong rồi mới chạy callback
 * Kiểm tra is_send_press, flag đang sinh của SillyTavern
 * Chờ tối đa 60 giây, quá thời gian thì ép chạy
 */
function waitForMainChatIdle(callback) {
  var maxWait = 60000;
  var interval = 500;
  var elapsed = 0;
  function check() {
    var isBusy = false;
    try {
      var tw = window.parent || window;
      /* is_send_press là flag toàn cục của SillyTavern, khi đang sinh là true */
      if (tw.is_send_press) isBusy = true;
      // [V10.4•2026-05-13] Sửa cùng loại vấn đề: trong lúc model phụ chạy callRawApi hoặc fetch độc lập,
      //   is_send_press có thể tạm thời false, nên kiểm tra thêm _yinqi_extra_gen_running và #mes_stop
      //   để tránh chèn nhầm tầng sự kiện thế giới vào khoảng hở giữa các lần gọi API độc lập.
      if (!isBusy && tw._yinqi_extra_gen_running === true) isBusy = true;
      if (!isBusy) {
        try {
          var stopBtn = tw.document && tw.document.getElementById("mes_stop");
          if (stopBtn && stopBtn.offsetParent !== null) isBusy = true;
        } catch (_eStop) {}
      }
    } catch (e) {}
    if (!isBusy || elapsed >= maxWait) {
      callback();
    } else {
      elapsed += interval;
      setTimeout(check, interval);
    }
  }
  check();
}

// ==================== Chèn tầng sự kiện song song ====================
function insertWorldEventAsFloor(eventData) {
  if (!eventData || !eventData.summary) return;
  /* Chèn trễ: chờ tầng chính sinh xong để tránh race */
  waitForMainChatIdle(function () {
    _doInsertWorldEventFloor(eventData);
  });
}

function _doInsertWorldEventFloor(eventData) {
  try {
    var targetWindow = window.parent || window;
    if (!targetWindow.SillyTavern || !targetWindow.SillyTavern.getContext)
      return;
    var context = targetWindow.SillyTavern.getContext();
    if (!context || !context.chat) return;

    var locationTag = eventData.location
      ? "【" + eventData.location + "】"
      : "";
    var timeTag = eventData.time ? "（" + eventData.time + "）" : "";
    var content =
      "<WorldEvent>\n" +
      "[Sự kiện song song: chuyện xảy ra ở nơi khác trong thế giới khi {{user}} không có mặt. Hệ quả nên gián tiếp ảnh hưởng cốt truyện sau đó (cảm xúc/quan hệ/foreshadow của nhân vật), nhưng cấm trực tiếp thuật lại quá trình sự kiện trong chính văn]\n" + 
      "\u26A1 " +
      locationTag +
      timeTag +
      "\n\n" +
      eventData.summary.replace(/^\s+/gm, "") +
      "\n</WorldEvent>" +
      "\n<UpdateVariable></UpdateVariable>"; // [V3.0] UpdateVariable rỗng để ngăn framework MVU xóa sạch stat_data

    // Tạo tầng độc lập, thân phận tin nhắn AI, AI có thể thấy
    var chat = context.chat;
    var newMessage = {
      name: context.name2 || "System",
      is_user: false,
      is_system: false,
      mes: content,
      extra: { isSmallSys: true },
      send_date: Date.now(),
      force_avatar: undefined,
    };

    _yqSetInsertFloor(true);
    try {
      chat.push(newMessage);

      // Kích hoạt refresh UI và lưu
      if (typeof context.saveChat === "function") {
        context.saveChat();
      }
      // Dùng addOneMessage để refresh UI nếu có
      if (typeof context.addOneMessage === "function") {
        context.addOneMessage(newMessage, { scroll: false });
      } else {
        // Fallback: refresh hiển thị chat thủ công
        if (typeof context.printMessages === "function") {
          context.printMessages();
        }
      }
    } finally {
      _yqSetInsertFloor(false);
    }

    console.log("[Sự kiện song song] Đã chèn tầng độc lập");
  } catch (e) {
    _yqSetInsertFloor(false);
    console.warn("[Sự kiện song song] Chèn tầng thất bại:", e);
  }
}

// ==================== Bơm tóm tắt tin nhắn NPC vào ngữ cảnh SillyTavern ====================
function _yqAwPriorityRank(p) {
  var x = String(p || "mid");
  if (x === "critical") return 4;
  if (x === "high") return 3;
  if (x === "mid") return 2;
  return 1;
}
function _yqAwEstimateTokensByChars(text) {
  return Math.max(0, Math.ceil(String(text || "").length * 1.0));
}
function _yqAwApplyTokenBudget(segments, cfg) {
  var rows = Array.isArray(segments) ? segments.slice() : [];
  var budget = Math.max(
    1000,
    Math.min(50000, Number(cfg && cfg.tokenBudgetTotal) || 10000),
  );
  var moduleCfg = (cfg && cfg.modules) || {};
  rows.sort(function (a, b) {
    var pr = _yqAwPriorityRank(b.priority) - _yqAwPriorityRank(a.priority);
    if (pr !== 0) return pr;
    var aw = Number((moduleCfg[a.key] && moduleCfg[a.key].weight) || 1);
    var bw = Number((moduleCfg[b.key] && moduleCfg[b.key].weight) || 1);
    if (bw !== aw) return bw - aw;
    return String(a.key || "").localeCompare(String(b.key || ""));
  });
  var used = 0;
  var kept = [];
  var dropped = [];
  for (var i = 0; i < rows.length; i++) {
    var seg = rows[i] || {};
    var t =
      Number(seg.estimatedTokens || _yqAwEstimateTokensByChars(seg.text)) || 0;
    var mCfg = moduleCfg[seg.key] || {};
    var reserve = Math.max(0, Number(mCfg.minReserveTokens) || 0);
    var rank = _yqAwPriorityRank(seg.priority);
    // 1) Cắt theo maxTokens từng module trước, null = không giới hạn
    var perMax =
      mCfg.maxTokens == null ? null : Math.max(60, Number(mCfg.maxTokens) || 0);
    if (perMax != null && t > perMax) {
      var perCut = String(seg.text || "").slice(0, perMax);
      if (perCut.trim()) {
        seg = Object.assign({}, seg, {
          text: perCut + "\n",
          estimatedTokens: _yqAwEstimateTokensByChars(perCut),
          sourceMeta: Object.assign({}, seg.sourceMeta || {}, {
            moduleCapped: true,
            moduleCap: perMax,
          }),
        });
        t = seg.estimatedTokens;
      } else {
        dropped.push({
          key: seg.key,
          reason: "empty_after_module_cap",
          estimatedTokens: t,
        });
        continue;
      }
    }
    // 2) Sau đó cắt theo tổng ngân sách
    if (used >= budget) {
      dropped.push({ key: seg.key, reason: "budget_full", estimatedTokens: t });
      continue;
    }
    if (used + t <= budget) {
      kept.push(seg);
      used += t;
      continue;
    }
    if (rank >= 3 || reserve > 0) {
      var remain = budget - used;
      var cut = String(seg.text || "").slice(0, Math.max(120, remain));
      if (cut.trim()) {
        var patched = Object.assign({}, seg, {
          text: cut + "\n",
          estimatedTokens: _yqAwEstimateTokensByChars(cut),
          sourceMeta: Object.assign({}, seg.sourceMeta || {}, {
            truncated: true,
          }),
        });
        used += patched.estimatedTokens;
        kept.push(patched);
      } else {
        dropped.push({
          key: seg.key,
          reason: "empty_after_cut",
          estimatedTokens: t,
        });
      }
    } else {
      dropped.push({
        key: seg.key,
        reason: "low_priority_budget_drop",
        estimatedTokens: t,
      });
    }
  }
  return { kept: kept, dropped: dropped, budget: budget, used: used };
}
function _injectNpcSummaryToContextImpl() {
  try {
    var cfg =
      typeof window.getAiAwarenessV2Config === "function"
        ? window.getAiAwarenessV2Config()
        : null;
    if (!cfg || cfg.enabled === false) return;
    var moduleCfg = cfg.modules || {};
    var segments = [];
    if (typeof window.yqBuildAwarenessSegmentsFromPhoneData === "function") {
      segments = segments.concat(
        window.yqBuildAwarenessSegmentsFromPhoneData(cfg) || [],
      );
    } else {
      var gen = window.npcMsgGen;
      if (gen && typeof gen.getMessagesSummaryForAI === "function") {
        var fallback = String(gen.getMessagesSummaryForAI() || "");
        if (fallback) {
          segments.push({
            key: "legacySummary",
            title: "Ghi chép xã hội điện thoại",
            priority: "mid",
            text: fallback,
            estimatedTokens: _yqAwEstimateTokensByChars(fallback),
            sourceMeta: { fallback: true },
          });
        }
      }
    }
    try {
      if (
        moduleCfg.unifiedCharacterMemory &&
        moduleCfg.unifiedCharacterMemory.enabled !== false &&
        typeof window.yqBuildUnifiedMemorySegment === "function"
      ) {
        var um = window.yqBuildUnifiedMemorySegment(
          moduleCfg.unifiedCharacterMemory,
        );
        if (um && um.text) segments.push(um);
      }
    } catch (_em) {}
    if (!segments.length) return;
    var plannedOrder = Array.isArray(cfg.moduleOrder) ? cfg.moduleOrder : [];
    if (plannedOrder.length > 0) {
      // Key chưa biết được xếp ổn định xuống cuối, tránh indexOf trả -1 gây rung thứ tự
      segments.sort(function (a, b) {
        var ia = plannedOrder.indexOf(a.key);
        var ib = plannedOrder.indexOf(b.key);
        if (ia < 0) ia = Number.POSITIVE_INFINITY;
        if (ib < 0) ib = Number.POSITIVE_INFINITY;
        return ia - ib;
      });
    }
    var budgeted = _yqAwApplyTokenBudget(segments, cfg);
    if (!budgeted.kept.length) return;

    // Thử bơm qua setExtensionPrompt của SillyTavern
    var tw = window.parent || window;
    if (tw.SillyTavern && tw.SillyTavern.getContext) {
      var ctx = tw.SillyTavern.getContext();
      if (ctx && typeof ctx.setExtensionPrompt === "function") {
        var hasHigh = budgeted.kept.some(function (s) {
          return _yqAwPriorityRank(s.priority) >= 3;
        });
        var header = hasHigh
          ? "[Thông tin hệ thống - ghi chép xã hội trên điện thoại của {{user}}, gồm ba cấp nội dung: \"thông tin bối cảnh\", \"thông tin tham khảo\", \"tham khảo cốt truyện quan trọng\". Ưu tiên thấp hơn input mới nhất của người chơi, cảnh cuối tuyến chính và thời gian/địa điểm MVU hiện tại; giao lưu online không bằng gặp mặt trực tiếp, khi xung đột chỉ dùng làm foreshadow]\n"
          : "[Thông tin hệ thống - ghi chép xã hội trên điện thoại của {{user}}, gồm hai cấp nội dung: \"thông tin bối cảnh\", \"thông tin tham khảo\". Ưu tiên thấp hơn input mới nhất của người chơi, cảnh cuối tuyến chính và thời gian/địa điểm MVU hiện tại; giao lưu online không bằng gặp mặt trực tiếp, khi xung đột chỉ dùng làm foreshadow]\n";
        var finalBody = budgeted.kept
          .map(function (s) {
            return String(s.text || "");
          })
          .join("\n");
        window._yqAwarenessLastInjection = {
          used: budgeted.used,
          budget: budgeted.budget,
          dropped: budgeted.dropped,
          kept: budgeted.kept.map(function (x) {
            return {
              key: x.key,
              estimatedTokens: x.estimatedTokens,
              priority: x.priority,
            };
          }),
        };
        ctx.setExtensionPrompt(
          "yinqi-npc-messages",
          header + finalBody,
          1, // extension_prompt_types.IN_CHAT (after scenario)
          3, // keep phone/social context as background so it does not override the latest main plot
        );
      }
    }
  } catch (e) {
    console.warn("[Bơm tin nhắn NPC] Thất bại:", e);
  }
}

/**
 * injectNpcSummaryToContext expose ra ngoài: coalesce trong cùng tick.
 *   Điểm gọi phân bố ở chat/forum/live/mvu/autogen/panels và nhiều nơi khác; một thao tác người dùng có thể
 *   kích hoạt 3-5 lần trong cùng microtask. Ở đây dùng microtask + marker một lần để gộp nhiều lần gọi
 *   thành một lần setExtensionPrompt, giảm tính toán lại vô hiệu và nhiễu log.
 *   Khi cần chạy "ngay lập tức", có thể gọi thẳng window._injectNpcSummaryToContextImpl().
 */
var _yqInjectNpcPending = false;
function injectNpcSummaryToContext() {
  if (_yqInjectNpcPending) return;
  _yqInjectNpcPending = true;
  var run = function () {
    _yqInjectNpcPending = false;
    try {
      _injectNpcSummaryToContextImpl();
    } catch (_runErr) {}
  };
  try {
    if (typeof Promise !== "undefined" && Promise.resolve) {
      Promise.resolve().then(run);
    } else {
      setTimeout(run, 0);
    }
  } catch (_scheduleErr) {
    setTimeout(run, 0);
  }
}
try {
  window._injectNpcSummaryToContextImpl = _injectNpcSummaryToContextImpl;
  window.injectNpcSummaryToContext = injectNpcSummaryToContext;
} catch (_exposeInjErr) {}


