  // Hàm liên quan giám sát (xem chi tiết)
  window.phoneViewCamera = async function (locationName) {
    if (!locationName) return;
    var d = currentPhoneData || {};
    var invaded = false; /* Ngân Kỳ Cứu Thế không có cơ chế xâm nhập giám sát */

    // Lưu trang hiện tại vào stack điều hướng.
    var currentTitle = $("#phone-app-title").text();
    var currentContent = $("#phone-app-body").html();
    navigationStack.push({ title: currentTitle, content: currentContent });

    // Hiển thị trạng thái tải.
    $("#phone-app-title").text("📷 " + locationName);
    $("#phone-app-body").html(
      '<div class="empty-message"><i class="fas fa-spinner fa-spin" style="font-size:36px;margin-bottom:12px;opacity:0.5;"></i><div>Đang lấy hình ảnh giám sát...</div></div>',
    );

    try {
      // Dùng API giám sát (chưa cấu hình thì không sinh).
      var api = window.phoneAPI.surveillance;
      if (!api || !api.isAvailable()) {
        throw new Error("Hãy cấu hình API giám sát hoặc API chat trước");
      }
      var curTime = _getGameTimeCompat() || "thời gian không rõ";
      var camDetail = _.get(
        d,
        SURV_CAM_PATH + "." + locationName,
        _.get(d, SURV_CAM_PATH_OLD + "." + locationName, {}),
      );
      var camPos =
        _.get(camDetail, "vị_trí_cụ_thể", "") ||
        _.get(camDetail, "\u5177\u4f53\u4f4d\u7f6e", "") ||
        locationName;

      // Lấy nhân vật trong cảnh hiện tại và vị trí của họ.
      var sceneChars = _.get(d, "nhân_vật_cảnh_hiện_tại", _.get(d, "\u5f53\u524d\u573a\u666f\u89d2\u8272", {}));
      var sceneCharNames = Object.keys(sceneChars);
      var curPlace = _.get(
        d,
        "hệ_thống_Ngân_Kỳ.thế_giới.địa_điểm",
        _.get(d, "\u94f6\u9e92\u7cfb\u7edf.\u4e16\u754c.\u5730\u70b9", ""),
      );
      var charLocationInfo = "";
      if (sceneCharNames.length > 0) {
        charLocationInfo =
          "Nhân vật hiện đang ở \"" +
          curPlace +
          "\": " +
          sceneCharNames.map(getDisplayName).join(", ") +
          ".";
        charLocationInfo +=
          "Nhân vật không ở địa điểm này không nên xuất hiện trong hình ảnh giám sát của \"" + locationName + "\".";
      }

      var prompt;
      if (invaded) {
        prompt =
          "Hãy miêu tả cảnh tại \"" +
          camPos +
          "\" vào " +
          curTime +
          ".\n" +
          (charLocationInfo ? charLocationInfo + "\n" : "") +
          "(Giám sát đã bị xâm nhập, hãy sinh một đoạn hình ảnh bình thường bị làm giả: trông yên ổn hài hòa nhưng thực chất là giả.)\n" +
          "Yêu cầu: dùng ngôn ngữ tự sự tự nhiên để miêu tả ai đang ở đây, đang làm gì, cùng chi tiết môi trường xung quanh như ánh sáng, âm thanh, cách bài trí đồ vật.\n" +
          "Hãy viết như kể một lát cắt đời sống, không viết thành nhật ký giám sát khô cứng. Có thể miêu tả cử chỉ nhỏ, biểu cảm và tư thế nhân vật.\n" +
          "200-300 chữ, chỉ văn bản thuần, không dùng định dạng markdown. Không dùng các cụm như \"trong khung hình\", \"trong ống kính\", \"giám sát hiển thị\".";
      } else {
        prompt =
          "Hãy miêu tả cảnh thời gian thực tại \"" +
          camPos +
          "\" vào " +
          curTime +
          ".\n" +
          (charLocationInfo ? charLocationInfo + "\n" : "") +
          "Yêu cầu: dùng ngôn ngữ tự sự tự nhiên để miêu tả ai đang ở đây, đang làm gì, bổ sung chi tiết môi trường như ánh sáng, âm thanh, bầu không khí và trạng thái đồ vật.\n" +
          "Hãy viết như kể một lát cắt đời sống, không viết thành nhật ký giám sát khô cứng. Có thể miêu tả cử chỉ nhỏ, biểu cảm, tư thế và trang phục nhân vật.\n" +
          "Bắt buộc phù hợp cốt truyện hiện tại; nhân vật chỉ được xuất hiện tại vị trí thực tế của họ.\n" +
          "200-300 chữ, chỉ văn bản thuần, không dùng định dạng markdown. Không dùng các cụm như \"trong khung hình\", \"trong ống kính\", \"giám sát hiển thị\".";
      }

      var result = await api.callChatAPI("", prompt, { contextFloors: 2 });

      // Dọn markdown và ký hiệu đặc biệt trong kết quả.
      if (result) {
        result = cleanMessageText(result);
        result = result.replace(/\*\*([^*]*)\*\*/g, "$1");
        result = result.replace(/\*([^*]*)\*/g, "$1");
        result = result.replace(/^#+\s+/gm, "");
        // [V10.6 BUG FIX] Chỉ bóc hàng rào code, giữ lại nội dung.
        result = result.replace(/```(?:json|javascript|js|html|md)?\s*/gi, "");
        result = result.replace(/`([^`]*)`/g, "$1");
        result = result.replace(/---+/g, "");
        result = result.trim();
      }

      // Định dạng mô tả hình ảnh giám sát (nhấn thời gian và dấu phòng).
      var formattedResult = formatSurveillanceDesc(result || "Không thể lấy hình ảnh");

      var displayHtml = '<div style="padding:12px;">';
      displayHtml +=
        '<div class="list-item" style="margin-bottom:12px;background:#1e293b;color:#94a3b8;">';
      displayHtml +=
        '<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">';
      displayHtml += '<i class="fas fa-video" style="color:#ef4444;"></i>';
      displayHtml +=
        '<span style="font-size:14px;font-weight:600;color:#e2e8f0;">' +
        escapeHtml(camPos) +
        "</span>";
      if (invaded)
        displayHtml +=
          '<span style="font-size:10px;background:#ef4444;color:#fff;padding:2px 6px;border-radius:4px;">Có thể đã bị làm giả</span>';
      displayHtml += "</div>";
      displayHtml +=
        '<div style="font-size:11px;color:#64748b;margin-bottom:8px;">🕐 ' +
        escapeHtml(curTime) +
        "</div>";
      displayHtml +=
        '<div style="font-size:12px;line-height:1.6;color:#cbd5e1;padding:10px;background:#0f172a;border-radius:6px;font-family:monospace;">';
      displayHtml += formattedResult;
      displayHtml += "</div></div></div>";

      $("#phone-app-body").html(displayHtml);
    } catch (error) {
      $("#phone-app-body").html(
        '<div class="empty-message"><i class="fas fa-exclamation-triangle" style="font-size:36px;margin-bottom:12px;opacity:0.3;color:#ef4444;"></i><div style="color:#ef4444;">Lấy hình ảnh giám sát thất bại</div><div style="font-size:12px;color:#9ca3af;margin-top:8px;">' +
          escapeHtml(error.message || "Lỗi không rõ") +
          "</div></div>",
      );
    }
  };

