/** Tự sinh phòng live */
async function autoGenLive() {
  var liveAPI = window.phoneAPI && window.phoneAPI.live;
  if (!liveAPI || !liveAPI.isAvailable()) return;
  if (typeof window.yqShouldRunAutoModule === "function") {
    var _liveModGuard = window.yqShouldRunAutoModule("live");
    if (!_liveModGuard || _liveModGuard.allowed !== true) {
      console.log(
        "[Guard nhất quán] Bỏ qua tự sinh live, lý do:",
        (_liveModGuard && _liveModGuard.reason) || "blocked",
      );
      return;
    }
  }
  if (_autoShouldSkipByTTL("autogen:live:last", 10000)) return;
  var agSettings = getAutoGenSettings("live");
  if (agSettings.showToast !== false && typeof toastr !== "undefined") {
    yqToast("info", "Đang tự sinh phòng live...", "📺 Live", { timeOut: 1500 });
  }
  try {
    await phoneGenerateLiveRooms();
    // Nếu hiện đang ở trang danh sách live, làm mới hiển thị.
    if (currentPanel === "live" && !_liveCurrentRoomId) {
      $("#phone-app-body").html(generateLiveListPanel());
      bindPanelButtons();
    }
    _autoMarkTTL("autogen:live:last", 10000);
  } catch (e) {
    if (typeof toastr !== "undefined")
      yqToast("error", "Tự sinh live thất bại: " + (e.message || ""), "📺 Live");
    console.warn("[Tự sinh live] Thất bại:", e);
  }
}

/**
 * Lấy số lượng tin nhắn hiện tại
 */
function getCurrentMessageCount() {
  try {
    // Trong môi trường iframe cần lấy SillyTavern từ parent.
    let targetWindow = window;
    if (window.parent && window.parent !== window) {
      try {
        if (window.parent.SillyTavern) {
          targetWindow = window.parent;
        }
      } catch (e) {}
    }

    if (targetWindow.SillyTavern && targetWindow.SillyTavern.getContext) {
      const context = targetWindow.SillyTavern.getContext();
      return context.chat ? context.chat.length : 0;
    }
  } catch (error) {}
  return 0;
}

/**
 * Cập nhật bộ đếm tin nhắn
 */
function updateMessageCount() {
  lastMessageCount = getCurrentMessageCount();
}

/**
 * Làm mới panel tin nhắn
 */
function refreshMessagesPanel() {
  try {
    if (typeof document !== "undefined" && document.hidden) return;
    // Chỉ làm mới khi đang mở panel tin nhắn.
    if (currentPanel === "messages" && currentPhoneData) {
      var gen = window.npcMsgGen;
      var didPartial = false;
      if (
        gen &&
        $("#phone-app-body .contact-item .yq-unread-badge").length > 0
      ) {
        didPartial = true;
        $("#phone-app-body .contact-item[data-id]").each(function () {
          var cid = String($(this).data("id") || "");
          var contactUnread = gen.getUnread(cid);
          var $badge = $(this).find(".yq-unread-badge");
          if ($badge.length === 0) return;
          if (contactUnread > 0) {
            $badge.text(String(contactUnread)).show();
          } else {
            $badge.text("").hide();
          }
        });
        if (window._msgPanelTab === "group") {
          $("#phone-app-body .contact-item[data-type='group']").each(
            function () {
              var gid = String($(this).data("id") || "");
              var gUnread = gen.getUnread("group_" + gid);
              var $badge = $(this).find(".yq-unread-badge");
              if ($badge.length === 0) return;
              if (gUnread > 0) {
                $badge.text(String(gUnread)).show();
              } else {
                $badge.text("").hide();
              }
            },
          );
        }
        try {
          window._yqPerfStats = window._yqPerfStats || {};
          window._yqPerfStats.messagesPanelPartialUpdates =
            (window._yqPerfStats.messagesPanelPartialUpdates || 0) + 1;
        } catch (_ep) {}
      }
      if (didPartial) return;
      // Sinh lại nội dung panel.
      const content = generateMessagesPanel(currentPhoneData);
      if (refreshMessagesPanel._lastHtml === content) return;
      refreshMessagesPanel._lastHtml = content;
      $("#phone-app-body").html(content);
      try {
        window._yqPerfStats = window._yqPerfStats || {};
        window._yqPerfStats.messagesPanelFullRenders =
          (window._yqPerfStats.messagesPanelFullRenders || 0) + 1;
      } catch (_ef) {}

      // Gắn lại sự kiện.
      bindMessagePanelEvents();
      bindPanelButtons();
    }
  } catch (error) {}
}

