var _liveSummaryGeneratingByRoom = {};
var _liveRoomJobSeq = {};
function _liveRoomId(roomOrId) {
  if (roomOrId && typeof roomOrId === "object")
    return String(roomOrId.id || "");
  return String(roomOrId || "");
}
function _liveIsCurrentRoom(roomOrId) {
  var roomId = _liveRoomId(roomOrId);
  return !!roomId && String(_liveCurrentRoomId || "") === roomId;
}
function _liveStartRoomJob(room, fieldName) {
  if (!room || !fieldName) return 0;
  var roomId = _liveRoomId(room);
  var key = roomId + "::" + fieldName;
  _liveRoomJobSeq[key] = (Number(_liveRoomJobSeq[key]) || 0) + 1;
  room[fieldName] = _liveRoomJobSeq[key];
  return _liveRoomJobSeq[key];
}
function _liveIsRoomJobCurrent(room, roomId, fieldName, seq) {
  roomId = _liveRoomId(roomId);
  if (!room || !roomId || String(room.id || "") !== roomId) return false;
  var fresh = typeof getLiveRoom === "function" ? getLiveRoom(roomId) : room;
  if (!fresh || fresh.isLive === false) return false;
  if (fieldName) {
    var key = roomId + "::" + fieldName;
    if (Number(_liveRoomJobSeq[key] || 0) !== Number(seq || 0)) return false;
  }
  return true;
}
