    if (String(r.hostName || "") !== n && String(r.characterRef || "") !== n)
      continue;
    var score = r.isLive === false ? 0 : 100;
    if (_liveCurrentRoomId && String(r.id || "") === String(_liveCurrentRoomId))
      score += 50;
    if (r.currentSceneImageId) score += 8;
    if (r.coverImageId) score += 4;
