/**
 * Lấy danh sách bạn bè có thể chọn.
 */
function getAvailableFriendsForGroup() {
  const friends = [];

  try {
    // Lấy bạn bè từ biến MVU.
    var friendsList = buildFriendsList(currentPhoneData);
    var fKeys = Object.keys(friendsList);
    for (var i = 0; i < fKeys.length; i++) {
      friends.push({
        id: "friend_" + fKeys[i],
        name: fKeys[i],
        identity: "",
      });
    }

    // Trích xuất bạn bè từ lịch sử chat.
    const chatFriends = extractFriendsFromChat();
    chatFriends.forEach((chatFriend) => {
      const exists = friends.some(
        (f) => f.id === chatFriend.id || f.name === chatFriend.name,
      );
      if (!exists) {
        friends.push({
          id: chatFriend.id,
          name: chatFriend.name,
          identity: "Lịch sử chat",
        });
      }
    });
  } catch (error) {}

  return friends;
}

/**
 * Tạo danh sách chọn bạn bè.
 */
function generateFriendsSelectionList(friends) {
  return friends
    .map(function (friend) {
      var lbl =
        typeof window.yqFriendGetPrimaryDisplayName === "function"
          ? window.yqFriendGetPrimaryDisplayName(friend.name)
          : getDisplayName(friend.name);
      return (
        '<div class="friend-selection-item" data-friend-id="' +
        escapeHtml(friend.id) +
        '" data-friend-name="' +
        escapeHtml(friend.name) +
        '" style="display: flex; align-items: center; padding: 8px; margin-bottom: 4px; border-radius: 6px; cursor: pointer; transition: all 0.2s;" onmouseover="this.style.background=\'#f3f4f6\'" onmouseout="this.style.background=\'transparent\'">' +
        '<input type="checkbox" class="friend-checkbox" value="' +
        escapeHtml(friend.id) +
        '" style="margin-right: 10px; width: 16px; height: 16px; cursor: pointer;">' +
        '<div style="flex: 1;">' +
        '<div style="font-size: 13px; font-weight: 500; color: #1f2937;">' +
        escapeHtml(lbl) +
        "</div>" +
        '<div style="font-size: 11px; color: #9ca3af; margin-top: 2px;">' +
        escapeHtml(friend.identity || "") +
        "</div></div></div>"
      );
    })
    .join("");
}

/**
 * Gắn sự kiện liên quan đến tạo nhóm chat.
 */
function bindCreateGroupEvents() {
  // Nút chọn tất cả.
  $("#select-all-friends-btn")
    .off("click")
    .on("click", function () {
      const $checkboxes = $(".friend-checkbox");
      const allChecked = $checkboxes.toArray().every((cb) => cb.checked);

      $checkboxes.prop("checked", !allChecked);
      $(this).text(allChecked ? "Chọn tất cả" : "Bỏ chọn tất cả");

      // Cập nhật phần hiển thị thành viên đã chọn.
      updateSelectedMembers();
    });

  // Chọn bạn bè.
  $(".friend-checkbox")
    .off("change")
    .on("change", function () {
      updateSelectedMembers();
    });

  // Nút tạo.
  $("#create-group-submit-btn")
    .off("click")
    .on("click", function () {
      createGroup();
    });

  // Nút xóa thành viên, dùng ủy quyền sự kiện.
  $("body")
    .off("click.removeMember")
    .on("click.removeMember", ".remove-member-btn", function (e) {
      e.stopPropagation();
      const friendId = $(this).data("friend-id");
      removeMember(friendId);
    });
}

/**
 * Cập nhật phần hiển thị thành viên đã chọn.
 */
function updateSelectedMembers() {
  const $container = $("#selected-members-container");
  const $checkboxes = $(".friend-checkbox:checked");

  // Giữ tag của bản thân.
  $container.html(`
        <div class="selected-member-tag" data-member="tôi" style="display: inline-flex; align-items: center; padding: 6px 12px; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; border-radius: 16px; font-size: 13px; font-weight: 500;">
            <span>Tôi (chủ nhóm)</span>
        </div>
    `);

  // Thêm bạn bè đã chọn.
  $checkboxes.each(function () {
    const $item = $(this).closest(".friend-selection-item");
    const friendName = $item.data("friend-name");
    const friendId = $item.data("friend-id");

    var _selLbl =
      typeof window.yqFriendGetPrimaryDisplayName === "function"
        ? window.yqFriendGetPrimaryDisplayName(friendName)
        : getDisplayName(friendName);
    $container.append(`
            <div class="selected-member-tag" data-member="${friendId}" style="display: inline-flex; align-items: center; padding: 6px 12px; background: #3b82f6; color: white; border-radius: 16px; font-size: 13px; font-weight: 500;">
                <span>${escapeHtml(_selLbl)}</span>
                <span class="remove-member-btn" data-friend-id="${friendId}" style="margin-left: 6px; cursor: pointer; opacity: 0.8;">✕</span>
            </div>
        `);
  });
}

/**
 * Xóa thành viên đã chọn.
 */
function removeMember(friendId) {
  $(`.friend-checkbox[value="${friendId}"]`).prop("checked", false);

  // Cập nhật hiển thị.
  updateSelectedMembers();
}

/**
 * Tạo nhóm chat rồi lưu vào chatMetadata.
 */
async function createGroup() {
  var groupName = $("#group-name-input").val().trim();
  var groupId = $("#group-id-input").val().trim();
  var $checkboxes = $(".friend-checkbox:checked");

  if (!groupName) {
    yqToast("error", "Vui lòng nhập tên nhóm chat");
    return;
  }
  if (!groupId || !/^\d+$/.test(groupId)) {
    yqToast("error", "Vui lòng nhập ID nhóm chat hợp lệ (chỉ gồm chữ số)");
    return;
  }
  if ($checkboxes.length === 0) {
    yqToast("error", "Vui lòng chọn ít nhất một thành viên nhóm");
    return;
  }

  var members = ["tôi"];
  $checkboxes.each(function () {
    var $item = $(this).closest(".friend-selection-item");
    var friendName = $item.data("friend-name");
    members.push(friendName);
  });
  var membersStr = members.join(", ");

  try {
    var groups = getSavedGroups();
    groups[groupId] = {
      name: groupName,
      members: membersStr,
      isDefault: false,
    };
    setSavedGroups(groups);

    yqToast("success", 'Nhóm chat "' + getDisplayName(groupName) + '" đã tạo thành công!');

    setTimeout(function () {
      closeAppPanel();
      if (currentPhoneData) {
        var content = generateMessagesPanel(currentPhoneData);
        $("#phone-app-body").html(content);
      }
    }, 500);
  } catch (error) {
    yqToast("error", "Tạo nhóm chat thất bại: " + error.message);
  }
}

/**
 * Popup xác nhận tùy chỉnh.
 * @param {Object} options - cấu hình popup
 * @param {string} options.title - tiêu đề
 * @param {string} options.message - nội dung thông báo
 * @param {string} options.icon - icon emoji
 * @param {Object} options.itemInfo - thông tin chi tiết vật phẩm, tùy chọn
 * @param {string} options.confirmText - chữ nút xác nhận
 * @param {string} options.cancelText - chữ nút hủy
 * @returns {Promise<boolean>} - lựa chọn của người dùng
 */
function showCustomConfirm(options = {}) {
  return new Promise((resolve) => {
    const {
      title = "Xác nhận thao tác",
      message = "Bạn chắc chắn muốn tiếp tục?",
      icon = "❓",
      itemInfo = null,
      confirmText = "Xác nhận",
      cancelText = "Hủy",
    } = options;

    // Dựng HTML thông tin vật phẩm, dùng style inline.
    let itemInfoHtml = "";
    if (itemInfo) {
      itemInfoHtml = `
                <div class="confirm-item-info" style="background:rgba(102,126,234,0.1);border:1px solid rgba(102,126,234,0.3);border-radius:12px;padding:16px;margin-bottom:24px;display:block;width:100%;box-sizing:border-box;">
                    <div class="confirm-item-name" style="display:block;width:100%;margin-bottom:8px;font-size:16px;font-weight:600;color:#f3f4f6;">
                        <span style="margin-right:8px;">${itemInfo.icon || "🎁"}</span>
                        <span>${getDisplayName(itemInfo.name || "Vật phẩm chưa rõ")}</span>
                    </div>
                    ${itemInfo.description ? `<div class="confirm-item-desc" style="display:block;width:100%;margin-bottom:8px;font-size:14px;color:#d1d5db;line-height:1.6;">${itemInfo.description}</div>` : ""}
                    ${
                      itemInfo.price !== undefined
                        ? `
                        <div class="confirm-item-price" style="display:block;width:100%;margin-bottom:0;font-size:15px;color:#fbbf24;font-weight:600;">
                            <span>💰 Giá:</span>
                            <span>${itemInfo.price} token nhiệm vụ</span>
                        </div>
                    `
                        : ""
                    }
                </div>
            `;
    }

    // Tính chiều rộng popup.
    const windowWidth = $(window).width();
    const bodyWidth = $("body").width();
    const containerWidth = windowWidth || bodyWidth || 400;
    let modalWidth = Math.min(Math.max(containerWidth * 0.9, 300), 480);
    if (modalWidth < 300 || isNaN(modalWidth)) {
      modalWidth = 400;
    }

    // Tạo HTML popup, đặt style inline trực tiếp trong HTML.
    const confirmHtml = `
            <div class="custom-confirm-overlay" style="position:fixed;top:0;left:0;right:0;bottom:0;width:100%;height:100%;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:100000;opacity:0;transition:opacity 0.3s ease-out;">
                <div class="custom-confirm-modal" style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);border-radius:20px;padding:2px;width:${modalWidth}px;max-width:480px;min-width:300px;box-shadow:0 12px 40px rgba(0,0,0,0.4);transform:translateY(30px) scale(0.95);opacity:0;transition:all 0.3s ease-out;display:block;box-sizing:border-box;margin:0 auto;">
                    <div class="custom-confirm-content" style="background:#1f2937;border-radius:18px;padding:28px 24px 20px;display:block;width:100%;box-sizing:border-box;min-height:100px;">
                        <div class="confirm-icon" style="width:64px;height:64px;margin:0 auto 20px;background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:32px;">${icon}</div>
                        <div class="confirm-title" style="font-size:22px;font-weight:700;margin-bottom:16px;color:#f3f4f6;text-align:center;display:block;width:100%;">${title}</div>
                        <div class="confirm-message" style="font-size:15px;line-height:1.7;color:#d1d5db;margin-bottom:24px;text-align:center;display:block;width:100%;">${message}</div>
                        ${itemInfoHtml}
                        <div class="confirm-buttons" style="display:flex;gap:12px;width:100%;">
                            <button type="button" class="confirm-btn confirm-btn-cancel" data-action="cancel">
                                ${cancelText}
                            </button>
                            <button type="button" class="confirm-btn confirm-btn-confirm" data-action="confirm">
                                ${confirmText}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        `;

    // Tạo phần tử popup.
    const $confirm = $(confirmHtml);

    // Thêm vào body của cửa sổ cha thay vì iframe, để khi đóng điện thoại popup vẫn còn thấy được.
    const targetBody =
      window.parent !== window ? $(window.parent.document.body) : $("body");
    $confirm.appendTo(targetBody);

    // Lấy phần tử modal và content.
    const $modal = $confirm.find(".custom-confirm-modal");
    const $content = $confirm.find(".custom-confirm-content");

    // Buộc trình duyệt repaint.
    $confirm[0].offsetHeight;

    // Kiểm tra kích thước.
    const confirmRect = $confirm[0].getBoundingClientRect();
    const modalRect = $modal[0].getBoundingClientRect();

    // Hiệu ứng fade in.
    setTimeout(() => {
      $confirm.css("opacity", "1");
    }, 10);

    // Hiệu ứng popup trượt lên.
    setTimeout(() => {
      $modal.css({
        transform: "translateY(0) scale(1)",
        opacity: "1",
      });
    }, 50);

    // Xử lý click nút, đồng thời gỡ keydown để tránh rò rỉ khi nhiều popup chồng lên.
    const targetDoc =
      window.parent !== window ? window.parent.document : document;
    const handleChoice = (confirmed) => {
      try {
        $(document).off("keydown", handleEsc);
        $(document).off("keydown", handleEnter);
        if (targetDoc !== document) {
          $(targetDoc).off("keydown", handleEsc);
          $(targetDoc).off("keydown", handleEnter);
        }
      } catch (_offErr) {}
      $confirm.fadeOut(200, () => {
        $confirm.remove();
        resolve(confirmed);
      });
    };

    // Gắn sự kiện.
    $confirm
      .find('[data-action="confirm"]')
      .on("click", () => handleChoice(true));
    $confirm
      .find('[data-action="cancel"]')
      .on("click", () => handleChoice(false));

    // Click lớp phủ để hủy.
    $confirm.on("click", (e) => {
      if ($(e.target).hasClass("custom-confirm-overlay")) {
        handleChoice(false);
      }
    });

    // Phím ESC để hủy, phần gỡ do handleChoice xử lý thống nhất.
    const handleEsc = (e) => {
      if (e.key === "Escape") handleChoice(false);
    };
    $(document).on("keydown", handleEsc);
    if (targetDoc !== document) $(targetDoc).on("keydown", handleEsc);

    // Phím Enter để xác nhận, phần gỡ do handleChoice xử lý thống nhất.
    const handleEnter = (e) => {
      if (e.key === "Enter") handleChoice(true);
    };
    $(document).on("keydown", handleEnter);
    if (targetDoc !== document) $(targetDoc).on("keydown", handleEnter);

    // Tự động focus nút xác nhận.
    setTimeout(() => {
      $confirm.find(".confirm-btn-confirm").focus();
    }, 100);
  });
}

// ==================== Khởi động ====================
$(() => {
  // Chờ dependency tải xong rồi khởi tạo giao diện điện thoại.
  (async () => {
    const MAX_WAIT_TIME = 30000;
    const CHECK_INTERVAL = 100;
    const startTime = Date.now();

    try {
      // Chờ hàm waitGlobalInitialized khả dụng.
      while (typeof waitGlobalInitialized !== "function") {
        if (Date.now() - startTime > MAX_WAIT_TIME) {
          console.error(
            "[Giao diện điện thoại] Chờ waitGlobalInitialized quá thời gian, thử khởi tạo trực tiếp",
          );
          initializeMobilePhone();
          return;
        }
        await new Promise((resolve) => setTimeout(resolve, CHECK_INTERVAL));
      }

      // Chờ Mvu khởi tạo xong.
      await waitGlobalInitialized("Mvu");
      initializeMobilePhone();
    } catch (e) {
      console.error("[Giao diện điện thoại] Khởi tạo thất bại:", e);
      // Dù lỗi vẫn thử khởi tạo chức năng cơ bản.
      try {
        initializeMobilePhone();
      } catch (e2) {
        console.error("[Giao diện điện thoại] Khởi tạo dự phòng cũng thất bại:", e2);
      }
    }
  })();
});

// Phím ESC đóng điện thoại hoặc trình xem toàn màn hình, có namespace để cleanupMobilePhone gỡ được.
$(document)
  .off("keydown.phoneEsc")
  .on("keydown.phoneEsc", function (e) {
    if (e.key === "Escape") {
      // Ưu tiên đóng trình xem hình nền toàn màn hình.
      const $viewer = $("#wallpaper-fullscreen-viewer");
      if ($viewer.hasClass("active")) {
        closeWallpaperFullscreen();
        return;
      }

      // Sau đó đóng giao diện điện thoại nếu chưa ghim.
      const overlay = $("#mobile-phone-overlay");
      if (overlay.hasClass("active") && !isPinned) {
        closeMobilePhone();
      }
    }
  });

// Dọn khi unload.
$(window).on("unload", () => {
  cleanupMobilePhone();
});

// Lắng nghe thông báo đổi dữ liệu từ panel hệ thống để refresh APP đang mở.
// Protocol v2: bên gửi có thể kèm { version, changedKeys?: string[] }.
//   - Không có changedKeys: tương thích hành vi cũ, refresh toàn bộ cache MVU.
//   - Có changedKeys: chỉ refresh khi trúng prefix key điện thoại quan tâm, giảm render vô ích.
// UI điện thoại hiện quan tâm snapshot MVU và cấu trúc con yinqi_phone; nhiệm vụ/cửa hàng đã chuyển đi.
var _YQ_META_INTEREST_PREFIX = [
  "stat_data",
  "yinqi_phone",
  "yinqi_",
  "yinqi_statdata_backup",
  "yinqi_guard_snapshot",
  "chat_avatars",
  "avatar",
  "player_avatar",
  "npc_messages",
  "monitor",
  "image_index",
  "groups",
  "known_friends",
];
function _yqNormalizeMetaChangedKey(k) {
  var s = String(k || "");
  if (s.indexOf("yinqi_phone.") === 0) return s.slice("yinqi_phone.".length);
  return s;
}
function _yqMetaInterested(keys) {
  if (!Array.isArray(keys) || !keys.length) return true; // Không cung cấp thì xem là toàn bộ.
  for (var i = 0; i < keys.length; i++) {
    var k = _yqNormalizeMetaChangedKey(keys[i]);
    for (var j = 0; j < _YQ_META_INTEREST_PREFIX.length; j++) {
      if (k.indexOf(_YQ_META_INTEREST_PREFIX[j]) === 0) return true;
    }
  }
  return false;
}
// [V5.3 P1 Fix - BUG-10] Hiển thị/ẩn lớp phủ rollback.
function _yqShowRollbackOverlay(show, reason) {
  try {
    var id = "yq-rollback-overlay";
    var el = document.getElementById(id);
    if (show) {
      if (!el) {
        el = document.createElement("div");
        el.id = id;
        el.style.cssText = [
          "position:fixed",
          "inset:0",
          "background:rgba(0,0,0,.55)",
          "backdrop-filter:blur(3px)",
          "-webkit-backdrop-filter:blur(3px)",
          "display:flex",
          "align-items:center",
          "justify-content:center",
          "z-index:2147483647",
          "pointer-events:auto",
          "color:#fff",
          "font-family:Microsoft YaHei,sans-serif",
          "font-size:14px",
          "letter-spacing:1px",
          "user-select:none",
        ].join(";");
        el.innerHTML =
          '<div style="background:rgba(10,15,26,.9);border:1px solid rgba(125,211,252,.3);border-radius:12px;padding:18px 26px;text-align:center;box-shadow:0 14px 34px rgba(0,0,0,.42);">' +
          '<div style="font-size:28px;margin-bottom:8px;animation:yqSpin 1s linear infinite;display:inline-block;">⏪</div>' +
          '<div id="yq-rollback-overlay-text">Đang rollback dữ liệu...</div>' +
          '<div style="font-size:10px;color:#6b7a96;margin-top:6px;">Vui lòng chờ, đừng thao tác</div>' +
          "</div>" +
          "<style>@keyframes yqSpin{from{transform:rotate(0)}to{transform:rotate(360deg)}}</style>";
        document.body.appendChild(el);
      }
      try {
        var _t = document.getElementById("yq-rollback-overlay-text");
        if (_t)
          _t.textContent =
            "Đang rollback dữ liệu..." + (reason ? " (" + reason + ")" : "");
      } catch (_tErr) {}
    } else {
      if (el && el.parentNode) el.parentNode.removeChild(el);
    }
  } catch (_ovErr) {}
}

window.addEventListener("message", function (e) {
  if (!e || !e.data) return;
  // Chỉ tin message từ trang cha để tránh frame khác giả mạo sự kiện.
  try {
    if (e.source !== window.parent) return;
  } catch (_srcErr) {
    return;
  }
  try {
    if (
      e.origin &&
      e.origin !== "null" &&
      window.location &&
      window.location.origin &&
      e.origin !== window.location.origin
    ) {
      return;
    }
  } catch (_oriErr) {
    return;
  }

  // [V5.3 P1 Fix - BUG-10] Xử lý message yinqi_rollback_lock.
  if (e.data.type === "yinqi_rollback_lock") {
    try {
      _yqShowRollbackOverlay(!!e.data.locked, String(e.data.reason || ""));
    } catch (_lkErr) {}
    return;
  }

  // [V5.3 P1 Fix - BUG-4] Xử lý message yinqi_rollback_complete: sau khi rollback xong thì reset về màn hình chính.
  if (e.data.type === "yinqi_rollback_complete") {
    try {
      // Reset trạng thái điều hướng để UI không kẹt ở trang con đã rollback.
      try {
        if (
          typeof navigationStack !== "undefined" &&
          Array.isArray(navigationStack)
        ) {
          navigationStack.length = 0;
        }
      } catch (_nsErr) {}
      try {
        if (typeof currentPanel !== "undefined") {
          window.currentPanel = null;
        }
      } catch (_cpErr) {}
      // Kích hoạt về màn hình chính nếu trang cung cấp goHome/closeApp.
      try {
        if (typeof window.goHome === "function") window.goHome();
      } catch (_ghErr) {}
      try {
        if (typeof window.closeApp === "function") window.closeApp();
      } catch (_caErr) {}
      // Ép refresh dữ liệu MVU.
      try {
        if (typeof fetchLatestMvuData === "function") fetchLatestMvuData(true);
      } catch (_fmErr) {}
      console.debug(
        "[UI điện thoại] Rollback hoàn tất, đã reset điều hướng về màn hình chính - floor=",
        e.data.floor,
      );
    } catch (_rcErr) {}
    return;
  }

  // [V5.3 P3 Fix - BUG-5] Xử lý message yinqi_rollback_storage_cleanup: dọn cache local sau floor.
  if (e.data.type === "yinqi_rollback_storage_cleanup") {
    try {
      var _floorBelow = Number(e.data.floorBelow || 0);
      // Dọn dữ liệu trạng thái tạm trong localStorage có floor > floorBelow.
      // Giữ lại dữ liệu cấu hình như API settings, tùy chọn UI, chủ đề.
      try {
        var _keysToCheck = [];
        for (var _i = 0; _i < localStorage.length; _i++) {
          var _key = localStorage.key(_i);
          if (!_key) continue;
          // Chỉ dọn key tạm liên quan đến floor, gồm marker _floor_ hoặc _f<number>_.
          if (/_floor_|_f\d+_|_yqTmp_|_phoneTmp_/i.test(_key)) {
            _keysToCheck.push(_key);
          }
        }
        _keysToCheck.forEach(function (k) {
          try {
            localStorage.removeItem(k);
          } catch (_rmErr) {}
        });
        if (_keysToCheck.length > 0) {
          console.debug(
            "[UI điện thoại] Rollback đã dọn key localStorage liên quan đến floor: " +
              _keysToCheck.length +
              " mục - floor >",
            _floorBelow,
          );
        }
      } catch (_lsErr) {}
    } catch (_scErr) {}
    return;
  }

  if (e.data.type !== "yinqi_meta_updated") return;
  // Thỏa thuận version: không có version thì xem là tương thích v1.
  var _ver = Number(e.data.version || 1);
  if (_ver < 1) return;
  try {
    try {
      window._yqPerfStats = window._yqPerfStats || {};
      window._yqPerfStats.metaPostMessageReceived =
        Number(window._yqPerfStats.metaPostMessageReceived || 0) + 1;
      if (e.data.seq != null)
        window._yqPerfStats.metaPostMessageLastSeq = Number(e.data.seq || 0);
      if (e.data.sentAt) {
        var _lat = Math.max(0, Date.now() - Number(e.data.sentAt || 0));
        window._yqPerfStats.metaPostMessageLastLatencyMs = _lat;
        window._yqPerfStats.metaPostMessageMaxLatencyMs = Math.max(
          Number(window._yqPerfStats.metaPostMessageMaxLatencyMs || 0),
          _lat,
        );
      }
    } catch (_perfIgnore) {}
    if (!_yqMetaInterested(e.data.changedKeys)) return; // Không liên quan thì bỏ qua render.
    if (typeof fetchLatestMvuData === "function") fetchLatestMvuData(true);
    // APP nhiệm vụ/cửa hàng/ba lô đã chuyển sang panel hệ thống, không cần refresh trong UI điện thoại.
  } catch (err) {
    try {
      console.debug(
        "[Giao diện điện thoại] yinqi_meta_updated refresh thất bại (đã bỏ qua):",
        err && err.message,
      );
    } catch (_ignore) {}
  }
});

// [V6.5.5 - guard giữ nút điện thoại sống - 2026-04-24]
//   Bối cảnh: một số đường biên như cleanupMobilePhone gọi nhầm, iframe lỗi, hoặc ST render lại DOM
//         có thể làm #mobile-trigger-btn bị xóa nhưng chưa khởi tạo lại, khiến người chơi mất nút điện thoại.
//   Chiến lược: sau 30s từ lần khởi động đầu, khi init ổn định, bắt đầu kiểm tra định kỳ; mỗi 15s kiểm tra DOM.
//         Nếu không có nút kích hoạt và initializeMobilePhone khả dụng thì tự động dựng lại, idempotent, không tác dụng phụ.
//   Lock 3s để chống gọi song song; _guardStarted chống đăng ký trùng.
//
// [V6.5.13 FIX - 2026-04-25 qtwx-mcp-4 đã kiểm chứng thực tế]


// ======== Ngân Kỳ Cứu Thế/thẻ nhân vật/phiên bản hiện tại/mở rộng tác phẩm/phone/_guard.js ========
//   Nguyên nhân gốc: script này chạy trong iframe UI điện thoại, nhưng #mobile-trigger-btn thật ra do
//         02_init.js dùng jQuery chèn vào document.body của trang cha, tức trang chính ST.
//         Bản cũ dùng `document.getElementById(...)` của chính iframe nên luôn trả null.
//         Guard cứ mỗi 15s lại phán đoán nhầm là nút bị mất rồi ép gọi initializeMobilePhone().
//         02_init.js:1501 xóa nút cũ trước, gồm cả điện thoại đang dùng, rồi dựng lại.
//         Biểu hiện: điện thoại nhỏ tự đóng liên tục, trang render lặp lại, nhìn như tự refresh,
//                  đồng thời nút cài đặt/điều chỉnh hiệu năng hiển thị chậm vì mỗi 15s lại render kẹt main thread.
//   Sửa: dùng `_yqGuardDoc`, lấy window.parent.document khi iframe cùng origin cho phép truy cập.
//         Dùng try-catch fallback; khi không truy cập được thì về document cục bộ.
//   Xác minh bằng chrome-devtools-mcp: sau khi tắt setInterval này, 35s không có event dom:removed nào.
(function () {
  var _guardStarted = false;
  var _guardLock = false;
  // Lấy tham chiếu document của trang cha, nơi nút điện thoại nhỏ được chèn; iframe TH-script cùng origin có thể truy cập.
  var _yqGuardDoc;
  try {
    _yqGuardDoc = (window.parent && window.parent !== window && window.parent.document)
      ? window.parent.document
      : document;
  } catch (_eGuardDoc) {
    _yqGuardDoc = document;
  }
  setTimeout(function () {
    if (_guardStarted) return;
    _guardStarted = true;
    setInterval(function () {
      if (_guardLock) return;
      try {
        // Mỗi lần đều đọc lại document trang cha để phòng khi ST đổi chat làm parent reference hết hiệu lực.
        var _doc;
        try {
          _doc = (window.parent && window.parent !== window && window.parent.document)
            ? window.parent.document
            : _yqGuardDoc;
        } catch (_eDoc) { _doc = _yqGuardDoc; }
        if (
          _doc &&
          !_doc.getElementById("mobile-trigger-btn") &&
          typeof initializeMobilePhone === "function"
        ) {
          _guardLock = true;
          try { console.warn("[Guard điện thoại nhỏ] Phát hiện mất nút kích hoạt, tự động dựng lại"); } catch (_) {}
          try { initializeMobilePhone(); } catch (eInit) {
            try { console.error("[Guard điện thoại nhỏ] Dựng lại thất bại:", eInit && eInit.message); } catch (_) {}
          }
          setTimeout(function () { _guardLock = false; }, 3000);
        }
      } catch (_eGuard) {}
    }, 15000);
    try { console.log("[Guard điện thoại nhỏ] Guard giữ sống đã bật (V6.5.13 sửa lệch document - khởi động 30s + kiểm tra mỗi 15s)"); } catch (_) {}
  }, 30000);
})();


